var internet_connected = window.navigator.onLine;
var before_internet_connected = internet_connected;
window.addEventListener('online', ()=>{ 
    /*끊김->연결로 변경될 때 호출*/
    internet_connected = window.navigator.onLine;
    console.log("다시연결됨");
});

window.addEventListener('offline', ()=>{ 
    /*연갤->끊김으로 변경될 때 호출*/
    internet_connected = window.navigator.onLine;
    console.log("다시끊김");
});

function C_AsyncCall(callurl, options, onComplete, onError) {
    
    if(!internet_connected && before_internet_connected != internet_connected){
        C_showToast("인터넷연결 끊김", "인터넷연결이 끊겼습니다. 네트워크 연결을 확인해 주세요", function () {});
        before_internet_connected = internet_connected;
        return;
    }else if(internet_connected && before_internet_connected != internet_connected){
         C_showToast("인터넷 연결됨", "인터넷이 연결되었습니다.", function () {});
        before_internet_connected = internet_connected;
    }

    if (!options) options = {};
    return $.ajax({
        url: callurl,
        method: 'POST',
        headers: {
            'Content-Type': 'application/x-www-form-urlencoded'
        },
        data: options,
        transformRequest: function (data) {
            return $.param(data);
        },
        success: function (data, status, xhr) {

            if (onComplete) onComplete(data);
        },
        error: function (xhr, status, err) {

            if (onError) onError(err);
        }
    });

}

function GoToPage(url, data) {
    var form = document.createElement('form');

    if (data != null) {
        var objs;
        objs = document.createElement('input');
        objs.setAttribute("type", "hidden");
        objs.setAttribute("name", "message");
        objs.setAttribute("value", JSON.stringify(data));
    }

    form.appendChild(objs);
    form.setAttribute('method', 'post');
    form.setAttribute('action', url);
    document.body.appendChild(form);
    form.submit();
}
var allmessages = [];
var servertime = "";

function CallHandler(type, data, success, error) {

    var url = "";
    switch (type) {
        
        case "adm_game":
            url = '../../../ssapi/adm_game.php';
            break;
        case "homepage":
            url = '../../../ssapi/homepage.php';
            break;
        case "login":
            url = '../../../ssapi/login_web.php';
            break;
        case "logout":
            url = '../../../ssapi/logout_web.php';
            break;
        case "getdata":
            url = '../../../ssapi/getdata.php';
            break;
        case "push_message":
            url = '../../../ssapi/push_message.php';
            break;
        case "insert_xlsx_data":
            url = '../../../ssapi/insert_xlsx_data.php';
            break;
        case "insert_xlsx_membershipdata":
            url = '../../../ssapi/insert_xlsx_membershipdata.php';
            break;
        case "upload_xlsx_to_userready":
            url = '../../../ssapi/upload_xlsx_to_userready.php';
            break;
        case "check_beacon_log":
            url = '../../../ssapi/check_beacon_log.php';
            break;
        case "adm_get":
            url = '../../../ssapi/adm_get.php';
            break;
        case "getptrule":
            url = '../../../ssapi/getptrule.php';
            break;
        case "terms":
            url = '../../../ssapi/terms.php';
            break;
        case "my_payroll_history":
            url = '../../../ssapi/my_payroll_history.php';
            break;
        case "change_membership":
            url = '../../../ssapi/change_membership.php';
            break;
        case "my_gxreservation":
            url = '../../../ssapi/my_gxreservation.php';
            break;
        case "my_teacher_reservation":
            url = '../../../ssapi/my_teacher_reservation.php';
            break;
        case "my_reservation":
            url = '../../../ssapi/my_reservation.php';
            break;
    }
    
//    if(type != "check_beacon_log")console.log("aatype "+type+" data.type "+data.type);
    if (!(type == "check_beacon_log" || type == "homepage" || type == "adm_get" && data.type && data.type == "reset_password" || type == "adm_get" && data.type && data.type == "check_reset_password")) {
        C_ShowLoadingProgress();
    }
    
    

    if (type != "check_beacon_log" && typeof (isSession) == 'function') isSession();
    C_AsyncCall(url, data, function (res) {

        if (type == "check_beacon_log") {
            checkReservationAllMessageSend(res.time);
        }
        C_HideLoadingProgress();
        if (success) success(res);

    }, function (err) {
        C_HideLoadingProgress();
        if (error) error(err);

    });
}

var is_auto_message_sending = false;

function checkReservationAllMessageSend(time) {

    var json = null;
    for (var i = 0; i < allmessages.length; i++) {
        var rmessage = allmessages[i];
        if (rmessage.issended == "ready" && compare_date(rmessage.startday, getNowDateTime()) == -1) {
            allmessages[i].issended = "sended";
            json = rmessage;

            break;

        }
    }
    
    


    //1초마다 호출되므로 한번에 1개의 메세지 뭉치만 보낸다. 

    //예약된 메세지들을 보낸다.
    if (json != null) {
        var rand = Math.floor(Math.random() * 900);
        setTimeout(function () {
            autoPushMessage(json);
        }, rand);

    }
    //60초마다 호출
    if(homepage_cnt %60 == 0)
        checkHomePage();

     homepage_cnt++;
    if(homepage_cnt > 10000)homepage_cnt = 0;
}
var homepage_cnt = 0;

function checkHomePage(callback){
    if(auth < AUTH_OWNER)return;
    var senddata = {
        type: "gethomepagedata",
        uid : global_uid
    }
    CallHandler("homepage", senddata, function (res) {
//        console.log("homepage res is ",res);
        var code = parseInt(res.code);
        if(code == 100){
            homepage_data = res.message;
            updateHeaderHomePageButton(res.message);
            if(callback)callback(res.message);
        }
    }, function (err) {    
    });
   
}
//가입요청버튼 숫자를 입력한다.
function updateHeaderHomePageButton(rows) {
    var newcnt = 0;
    for(var i = 0 ; i < rows.length;i++){
        if(rows[i].homechecked == 0){
            newcnt++;
        }
    }
    if(newcnt > 0){
        var btn_homerequest = document.getElementById("btn_homerequest");
        if(newcnt > 10)newcnt = 10;
        var icons = ["","①","②","③","④","⑤","⑥","⑦","⑧","⑨","ⓤ"];
        
        btn_homerequest.innerHTML = "요청"+"&nbsp;&nbsp;<span style='font-size:16px;color:#ff8888'>"+icons[newcnt]+"</span>";
    }
}
