//오직 푸시고객,SMS고객 데이타를 가져온다.
function getCustomUsers(key, title, message, stime, etime, callback) {
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");


    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "getcustomusers",
        value: {
            "title": title,
            "message": message,
            "sendtype": key,
            "starttime": stime,
            "endtime": etime
        }
    }
    CallHandler("adm_get", senddata, function (res) {
        callback(res);
    }, function (err) {
        callback(null);
    });
}
