function autoPushMessage(json) {
    //    var global_mypoint = 0;
    //    var global_sms_sendprice = 0;//sms건당금액
    //    var global_lms_sendprice = 0;//lms건당금액
    //    var global_push_sendprice = 0;//푸시건당금액
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");




    //    C_SendWorker("autopushmessage",datas,functon(type,datas){
    //                     
    //    });
    clog("json is ", json);
    getMessageUsers(json, function (res) {
        var code = parseInt(res.code);
        if (code == 100) {
            allmessages = res.message;
            var sms_users = res.sms_users;
            var push_users = res.push_users;




            var smsuser_len = 0;
            var pushuser_len = 0;
            if (json.messagetype == "phone" || json.messagetype == "app_phone")
                smsuser_len = sms_users.length;
            if (json.messagetype == "app" || json.messagetype == "app_phone")
                pushuser_len = push_users.length;


            if (sendPointCheck(smsuser_len, pushuser_len, json.message)) {

                if (json.messagetype == "app" || json.messagetype == "app_phone") {
                    sendAppPushMessage(json.startday, push_users);
                }

                if (json.messagetype == "phone" || json.messagetype == "app_phone" || json.messagetype == "all_phone") {
                    sendSMSMessage(json.startday, sms_users);
                }


                if (typeof (setAllMessages) == 'function') {
                    clog("setAllMessages!!");
                    setAllMessages();
                }

            }



        }
    });
}


////예약된 앱메세지들을 보낸다.
function sendAppPushMessage(senddate, userinfos) {

    //개인으로 보낼때
    var push_users_token = [];
    var push_titles = [];
    var push_messages = [];

    //real
    for (var i = 0; i < userinfos.length; i++) {
//        var title = replaceEnterToBR(userinfos[i].message_title);
//        var msg = replaceEnterToBR(userinfos[i].message_message);
        
        push_titles.push(userinfos[i].message_title);
        push_messages.push(userinfos[i].message_message);
        push_users_token.push(userinfos[i].mem_fcmtoken);

    }

    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");
    var len = userinfos ? userinfos.length : 0;
    var pushdata = {
        "groupcode": groupcode,
        "centercode": centercode,
        "titles": push_titles,
        "messages": push_messages,
        "tokens": push_users_token,
        "clickaction": ""
    };
    clog("push_messages , ", push_messages);
    sendReservationPushMessages(senddate, pushdata, len);
}

function decodeUTF8(str) {
    // 특수문자도 포함할 경우  decodeURIComponent(str) 를 사용. 

    return decodeURI(str);
}

function encodeUTF8(str) {
    // 특수문자도 포함할 경우  encodeURIComponent(str) 를 사용.
    return encodeURI(str);
}


////예약된 SMS메세지들을 보낸다.
function sendSMSMessage(senddate, userinfos) {

    //개인으로 보낼때
    var sms_users_phone = [];
    var sms_titles = [];
    var sms_messages = [];
    var len = userinfos ? userinfos.length : 0;
    for (var i = 0; i < userinfos.length; i++) {
        sms_titles.push(userinfos[i].message_title);
        sms_messages.push(userinfos[i].message_message);
        sms_users_phone.push(userinfos[i].mem_phone);
    }

    var smsdata = {
        "titles": sms_titles,
        "messages": sms_messages,
        "phones": sms_users_phone,
        "clickaction": ""
    };
    //    clog("smsdata , "+smsdata);

    sendReservationSMSMessages(senddate, smsdata, len);
}

function sendReservationPushMessages(senddate, pushdata, len, success,error) {
    
    //real
    for (var i = 0; i < pushdata.length; i++) {
        pushdata.titles[i] = replaceEnterToBR(pushdata.titles[i]);
        pushdata.messages[i] = replaceEnterToBR(pushdata.messages[i]);
    }
    
    
    //여러명일때는 worker 를 사용하여 보낸다.
    if (len > 1) {
        var groupcode = getData("nowgroupcode");
        var centercode = getData("nowcentercode");

        var datas = {
            "groupcode": groupcode,
            "centercode": centercode,
            "uid": global_uid,
            "id": global_id,
            "value": pushdata
        }
//        clog("PUSH len is " + len);
        C_SendWorker("sendpushmessages", datas, function (res) {
            var result = JSON.parse(res);
            var code = parseInt(result.code);
            if (code == 100) {
                getMYChargePoint();
                if(success)success(JSON.parse(res));
                if (len > 0) C_showToast("앱푸시 전송됨", senddate + "에 총 " + len + "명에게 앱푸시를 전송하였습니다. ", function () {});
            } else {
                
                alertMsg(res.message);
            }
            
        });
    } else {
        push_check(pushdata, function (res) {
            var code = parseInt(res.code);
            if (code == 100) {
                getMYChargePoint();
                if(success)success(JSON.parse(res));
                if (len > 0) C_showToast("앱푸시 전송됨", senddate + "에 총 " + len + "명에게 앱푸시를 전송하였습니다. ", function () {});
            } else {
                
                alertMsg(res.message);
            }
        }, function (err) {
            if(error)error(err);
            //            alertMsg("네트워크 에러 ",err);
        });
    }

}

function sendPushMessage(uid, mtitle, mmessage) {
    getUserData(uid, function (result) {
        var code = parseInt(result.code);
        if (code == 100) {
            var user = result.message;
            clog("user ", user);
            pushmessage_user(user.mem_fcmtoken, mtitle, mmessage, ClickAction.SHOW_NOTICE, function (res) {
                code = parseInt(res.code);
                if (code == 100) {
                    C_showToast("메세지 보내기 성공!", "성공적으로 메세지를 보냈습니다.", function () {});

                } else {
                    C_showToast("에러", res.message, function () {});
                }
            }, function (err) {
                alertMsg("네트워크 에러 ", err);
            });
        }
    });
}
