function C_showToast(title, message, callback, _delay, style) {
    var id = random_string();
    var bgcolor_title = "#2e313a";
    var fontcolor_title = "#a9a9a9";
    var fontsize_title = "13px";
    var bgcolor_body = "#23232b";
    var fontcolor_body = "white";
    var fontsize_body = "13px";
    var isshowclosebtn = false;

    var mytoastarea = document.getElementById("toastarea");
    if (style) {

        if (style.bgcolor_title) bgcolor_title = style.bgcolor_title;
        if (style.fontcolor_title) fontcolor_title = style.fontcolor_title;
        if (style.fontsize_title) fontsize_title = style.fontsize_title;

        if (style.bgcolor_body) bgcolor_body = style.bgcolor_body;
        if (style.fontcolor_body) fontcolor_body = style.fontcolor_body;
        if (style.fontsize_body) fontsize_body = style.fontsize_body;

        if (style.isshowclosebtn) isshowclosebtn = style.isshowclosebtn;
    }

    var top_padding = style ? "padding:0px 15px 0px 15px" : "padding-top:15px;padding-bottom:15px";
    var body_padding = style ? "" : "padding-top:15px;padding-bottom:15px";



    var delay = 3000;
    if (_delay) delay = _delay;
    var closebtn_display = isshowclosebtn ? "block" : "none";
    mytoastarea.innerHTML = "<div id='" + id + "' class='toast' role='alert'  style='backgroun-color:#00000000;border:0px;border-radius:10px;box-shadow: 0px 5px 15px 0px rgba(0, 0, 0, 0.5);'>" +
        "<div class='toast-header' style='width:250px;border-radius:10px 10px 0px 0px;background-color:" + bgcolor_title + ";color:" + fontcolor_title + ";font-size:" + fontsize_title + ";" + top_padding + "'>" +
        "<i class='fa-solid fa-bell' style='color:#0ffa80;width:16px;height:17px;float:left;margin-top:10px'></i>&nbsp;&nbsp;&nbsp;" + title + "<i class='fa-solid fa-xmark' style='position:absolute;color:#999aa7;width:10px;height:10px;margin-left:210px' onclick='toastclose(\"" + id + "\")' ></i>" +
        "</div>" +
        "<div class='toast-body' style='width:250px;border-radius:0px 0px 10px 10px;background-color:" + bgcolor_body + ";color:" + fontcolor_body + ";font-size:" + fontsize_body + ";padding:0px 15px 0px 15px;margin-top:-1px;" + body_padding + "'>" +
        message +
        "</div>" +
        "</div>" + mytoastarea.innerHTML;
    $("#" + id).toast({
        "delay": delay
    });
    $("#" + id).toast("show");
    $("#" + id).on('hidden.bs.toast', function () {

        $("#" + id).remove();
        if (callback) callback();

    });
}

function toastclose(id) {
    var toast = document.getElementById(id);
    toast.style.display = "none";
    toast.parentNode.removeChild(toast);
}
//isdeletecheck : 삭제되거나 양도된 회원권도 체크할지 여부
function C_isUsingCoupon(coupon, isdeletecheck) {
    var starttime = coupon.starttime;
    var endtime = getTotalEndtime(coupon);
    var date = new Date();
    var now_timestamp = date.getTime();
    var start = new Date(starttime);
    var start_timestamp = start.getTime();
    var end = new Date(endtime);
    var end_timestamp = end.getTime();

    //isdeletecheck = true 라면 삭제되거나 양도된 회원권은 무조건 0 를 리턴한다.
    if (isdeletecheck && coupon.isdelete && coupon.isdelete != "N") return 0;
    //    clog("now_timestamp "+now_timestamp+" start_timestamp "+start_timestamp+" end_timestamp "+end_timestamp);
    if (now_timestamp > start_timestamp && now_timestamp < end_timestamp) {
        //        clog("1 현재 운동중인 쿠폰");
        return 1;
    } else if (now_timestamp < start_timestamp) {
        //        clog("2 운동 시작할 예정인 쿠폰");
        return 2;
    } else {
        //        clog("0 운동끝난 쿠폰");
        return 0;
    }
}
