function page_login() {
    clog("login Click!");
    var input_email = document.getElementById('inputEmailAddress').value;
    var input_password = document.getElementById('inputPassword').value;
    //    clog("inputPassword", input_password);
    //                location.href = "index.php";


    var _data = {
        "email": input_email,
        "pass": input_password,

    };
    CallHandler("login", _data, function (res) {
        var code = parseInt(res.code);
        if (code == 100) {
            var authgroup = parseInt(res.message);
            var memsetting = res.memsetting && res.memsetting != "" && res.memsetting != "null" ? JSON.parse(res.memsetting) : null;
            if (authgroup > 1) {
                location.href = PAGE_ADMIN_MAIN;
            } else if (authgroup == 1 || authgroup == 0) {
                //일반유저그룹이라서 홈페이지쪽으로 이동한다.    
                //location.href = PAGE_HOME_PATH + PAGE_HOME_INDEX;
                location.href = PAGE_HOME_PATH +"dist/"+ PAGE_RESERVATION;
            } else {
                location.href = PAGE_ADMIN_401; //권한이 낮아서 로그인 할 수 없음
            }

        } else {
            alertMsg(res.message);
        }


    }, function (err) {
        alertMsg("네트워크 에러 ");

    });



}


function startBeaconLog() {
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");

    if (groupcode != null && centercode != null) {
        beforeids = [];
        beforeindex = 0;
        if (beacon_timer != null) {
            clearInterval(beacon_timer);
        }

        beacon_timer = setInterval(function () {
            check_beacon_log(groupcode, centercode);
        }, 1000);
    }
}

function stopBeaconLog() {
    clearInterval(beacon_timer);
}
function getResetCode(_id){
    var id = parseInt(_id);
   
    var daytimestamp = 60*60*24;
    var now = new Date();
    var hour = now.getHours();
    var code = parseInt(Math.floor(Date.now() / 1000)/daytimestamp)*hour*id;
   
    return code;
}

var beacon_timer = null;
var beforeids = [];
var beforeindex = -1;

var todayinputlist = [];

function check_beacon_log(groupcode, centercode) {
    
  
    var data = {
        groupcode: groupcode,
        centercode: centercode,
        //        beforeid: beforeid,
        beforeindex: beforeindex
    }
    CallHandler("check_beacon_log", data, function (res) {
        var code = parseInt(res.code);

        if (code == 100) {

            var arr = res.message;
//            console.log("check_beacon_log res",res);
            //            arr = trim_sort_2array(arr,"userid"); //neel_중복출석

            todayinputlist = arr;
            var len = arr ? arr.length : 0;
            document.getElementById("listview_input").innerHTML = "";
            
            var inputcount = parseInt(getData("inputcount_" + centercode));
            var inputdate = getData("inputdate_" + centercode);
            var input_datecount = inputdate + "_" + inputcount;
            var glen = getToday() + "_" + len;
            for (var i = 0; i < len; i++) {

                if (i >= inputcount && input_datecount != glen) //neel_중복출석
                    if (i == len - 1) showLoginUser(centercode, arr[i], i);

                //if (i >= inputcount && input_datecount != glen && !isBeforeID(arr[i].userid))   //real
                //showLoginUser(centercode,arr[i],i);//real
            }

            saveData("inputcount_" + centercode, len);
            saveData("inputdate_" + centercode, getToday());

            arr = trim_sort_2array_subkey(arr, "userid", "date"); //neel_중복출석
            var trimlen = arr ? arr.length : 0;
            for (var i = 0; i < trimlen; i++) {

                //좌측하단 입장고객 리스트
                inputlist(arr[i].gender, arr[i].username, arr[i].date, arr[i].userid, arr[i].memberstatus);
            }

        }
        beforeindex = len;

    }, function (err) {
        //        if(!beforeid)beforeid="null";
    });
}

function showLoginUser(centercode, inputlog, i) {
    //    var title = "<div style='width:100%;height:auto'><text style='float:left'>"+inputlog.centername+"</text><br><text style='float:left;font-size:13px;color:blue'>"+ inputlog.date+" 입장</text></div>";
    var title = "<div style='width:100%;height:55px;padding-top:10px'><text style='float:left;font-size: 13px; color:#ffffff;font-weight:500;'>" + inputlog.centername + " 입장</text><br><text class='fmont' style='float:left;font-size: 13px; color:#a5a5b3;font-weight:500;margin-top:-1px '>" + inputlog.date + "</text></div>";
    //     var title = "<div style='float:left;font-size: 13px; color:#ffffff;font-weight:500;'>"+inputlog.centername+" 입장</div><br><br><div class='fmont' style='float:left;font-size: 13px; color:#a5a5b3;font-weight:500;margin-top:-5px '>"+ inputlog.date+"</div>";
    var now = new Date();
    var now_timestamp = now.getTime();

    var usertime = new Date(inputlog.date);
    var user_timestamp = usertime.getTime();
    var gabtime = now_timestamp - user_timestamp;
    if (gabtime < 30000) {
        getUserData(inputlog.userid, function (res) {
            var code = parseInt(res.code);
            if (code == 100) {
                var user = res.message[0];
                
                var now_using_coupon = user.mem_membership && user.mem_membership != "null"? getNowMembershipCoupon(JSON.parse(user.mem_membership)) : "";
                var mbsname = now_using_coupon != "" ? now_using_coupon.mbsname : "-";
                var starttime = now_using_coupon != "" ? now_using_coupon.starttime : "-";
                var endtime = now_using_coupon != "" ? getTotalEndtime(now_using_coupon) : "-";
                var alert_txt = getLoginAlert(user, centercode);
                var message = getLoginUserTable(user.mem_uid, user.mem_userid, user.mem_username, user.mem_birth, user.mem_phone, mbsname, starttime, endtime, alert_txt);


                var bodycolor = inputlog.memberstatus == "O" || inputlog.memberstatus == "I" ? "#ff4444" : "#23232b";
                var style = {
                    bgcolor_title: "#2e313a",
                    bgcolor_body: bodycolor,
                    isshowclosebtn: true
                };
                //
                if (inputlog.memberstatus != "N") {
                    var color = inputlog.memberstatus == "H" ? "#ee8888" : "#cacaca";
                }

                var toast_time = inputlog.memberstatus == "O" || inputlog.memberstatus == "I" ? 30000000 : 30000;
                C_showToast(title, message, function () {}, toast_time, style);
                findPlaySound(inputlog.memberstatus, inputlog.date);
            }
        });
    }
}

function getLoginAlert(user, centercode) {
    var rtxt = "";
    var coupons = getNowAfterCoupons(user);
    var lastcoupon = coupons[coupons.length-1];
    var endtime = lastcoupon ? getTotalEndtime(lastcoupon) : getToday();
    var newlockers = user.mem_newlockers;
    var reservation = user.mem_reservation ? JSON.parse(user.mem_reservation) : "";
    if (endtime) {
        var dday = getDay(endtime, getToday());
        if (dday <= 0 && dday > -15) {
            rtxt += "회원권 기간임박 " + Math.abs(dday) + "일 남음<br>";
        } else if (dday > 0) {
            rtxt += "회원권 " + Math.abs(dday) + "일 지남<br>";
        }
    }

    if (newlockers)
        for (var i = 0; i < newlockers.length; i++) {
            var locker = newlockers[i];
            if (locker.endtime) {
                var locker_dday = getDay(locker.endtime, getToday());
                if (locker_dday <= 0 && locker_dday > -15) {
                    rtxt += locker.num + "번 라커 기간임박 " + Math.abs(locker_dday) + "일 남음<br>";
                } else if (locker_dday > 0) {
                    rtxt += "라커기간종료 " + Math.abs(locker_dday) + "일 지남<br>";
                }
            }
        }
    if (reservation && reservation.length > 0) {
        var cendtime = reservation[0].endtime;
        var idx = 0;
        for (var i = 0; i < reservation.length; i++) {

            if (compare_date(cendtime, reservation[i].endtime) == 1) {
                cendtime = reservation[i].endtime;
                idx = i;
            }
        }
        if (reservation[idx].mbsusecentercode == centercode) {
            if (reservation[idx].endtime) {
                var pt_dday = getDay(reservation[idx].endtime, getToday());
                if (pt_dday <= 0 && pt_dday > -15) {
                    rtxt += "PT 기간임박" + pt_dday + "일 남음<br>";
                }
            }
        }
    }

    return rtxt;
}

function findPlaySound(type, date) {
    var filename = "./sound/user_F.mp3";
    if (type) {
        switch (type) {
            case "N": //일반회원
                filename = "./sound/user_F.mp3";
                break;
            case "O": //기간종료유저
                filename = "./sound/enduser_F.mp3";
                break;
            case "H": //홀딩유저
                filename = "./sound/holdinguser_F.mp3";
                break;
            case "I": //회원권이 있으나 아직 시작하지 않은 회원
                filename = "./sound/nocoupon.mp3";
                break;
        }
    }
    playSound(filename);
}

