function isBeforeID(id) {
    var flg = false;
    var data = {
        "date": getToday(),
        "id": id
    };
    var todaybeforeids = [];
    for (var i = 0; i < beforeids.length; i++) {
        if (beforeids[i].date == getToday())
            todaybeforeids.push(beforeids[i]);
    }
    beforeids = todaybeforeids;
    for (var i = 0; i < beforeids.length; i++) {
        if (beforeids[i].date == getToday() && beforeids[i].id == id) {
            flg = true;
            break;
        }
    }
    if (!flg) beforeids.push(data);

    return flg;
}

