var tutorial_status = 0;
var tutorial_interval = null;

function initTutorial() {

    getGroupData(function (res) {
        var code = parseInt(res.code);
        if (code == 100) {

            tutorial_status = res.message.gr_tutorialstatus ? parseInt(res.message.gr_tutorialstatus) : 0;

            if (tutorial_status < TS.FINISH) {
                if (auth >= AUTH_OPERATOR) {
                    if (tutorial_status <= TS._2_SETTING) {
                        tutorial_status = 0;
                        tutorialHandler();
                    } else {
                        showTutorialInitPopup(function () {
                            hideModalDialog();
                        });
                    }

                } else {
                    showTutorialLowUserPopup();
                }
            }
        }
    });


}

