function getTutorialLabelTag(x, y, str) {
    var tag = str ? "<label id='label_tutorial_order' style='margin-left:" + x + "px;margin-top:" + y + "px;color:white;font-size:20px;font-weight: 500;border-radius:20px;background-color:#14141429;border:0px;padding:13px 24px 13px 24px'>" + str + "</label>" : "";
    return tag;
}

function getTutorialPigArrow(x, y, rotate) {
    var rotate_tag = rotate ? "transform: rotate(" + rotate + "deg);" : "";
    var tag = "<img id='img_pigarrow' src='./img/pigani/tutorial_pigarrow_" + anim_pigarrow_cnt + ".png' style='position:absolute;margin-left:" + x + "px;margin-top:" + y + "px;" + rotate_tag + "'/>";
    return tag;
}
var anim_pigarrow_interval = null;
var anim_pigarrow_cnt = 0;
var before_tutorial_status = 0;

function animPigArrow() {

    if (before_tutorial_status != tutorial_status) {
        before_tutorial_status = tutorial_status;
        anim_pigarrow_cnt = 0;
        anim_pigarrow_interval = setInterval(function () {
            var img_pigarrow = document.getElementById("img_pigarrow");
            if (img_pigarrow) {
                anim_pigarrow_cnt++;
                if (anim_pigarrow_cnt < 14) {
                    img_pigarrow.src = "./img/pigani/tutorial_pigarrow_" + anim_pigarrow_cnt + ".png";
                } else {

                    clearInterval(anim_pigarrow_interval);
                    anim_pigarrow_cnt = 13;
                }
            }
        }, 50);
    }
}

