//설정팝업이 떴을때튜토리얼을 다음단계로 이동하기위한
function updateSetTutorialStatus() {
    if (tutorial_status == TS._6_DEFAULTSETTING)
        setTutorialStatus(TS._7_SETLOCKERPRICE);
    else if (tutorial_status == TS._7_SETLOCKERPRICE)
        setTutorialStatus(TS._9_CREATELOCKER);
    else if (tutorial_status == TS._11_SENDCOUPONPRICE)
        setTutorialStatus(TS._13_SETTINGSAVEPOPUP);
    else if (tutorial_status == TS._18_SETTINGGXLESSION)
        setTutorialStatus(TS._19_SETTINGSAVEPOPUP);
    else if (tutorial_status == TS._13_SETTINGSAVEPOPUP)
        setTutorialStatus(TS._14_SIGNUPTRANER);
    else if (tutorial_status == TS._19_SETTINGSAVEPOPUP)
        setTutorialStatus(TS._20_GOTOGXPAGE);
    else if (tutorial_status == TS._20_GOTOGXPAGE)
        setTutorialStatus(TS._21_CLICKGXDATE);
    else if (tutorial_status == TS._21_CLICKGXDATE)
        setTutorialStatus(TS._22_INSERTGXROOM);
    else if (tutorial_status == TS._22_INSERTGXROOM)
        setTutorialStatus(TS._23_INSERTROOMPOPUP);
    //         setTutorialStatus(TS._24_GXGROUPCOPY);
    else if (tutorial_status == TS._23_INSERTROOMPOPUP)
        setTutorialStatus(TS._24_GXGROUPCOPY);
    else if (tutorial_status == TS._24_GXGROUPCOPY)
        setTutorialStatus(TS._25_SETPAYROLL);
    else if (tutorial_status == TS._25_SETPAYROLL)
        setTutorialStatus(TS._26_INSERTPAROLLDATA);
    else if (tutorial_status == TS._26_INSERTPAROLLDATA)
        setTutorialStatus(TS._27_SETPAROLLPOPUP);
    else if (tutorial_status == TS._27_SETPAROLLPOPUP) {

        finish_tutorial_popup();
    }



}
//좌측 nav 메뉴 폈다 접었다하기  isdown : true : 펴기 , false : 접기
function navRollUpDown(id, isdown) {
    if (!isdown) {
        var nav_menu = document.getElementById(id);
        if (nav_menu.className.indexOf("show") >= 0) nav_menu.className = nav_menu.className.replace("show", "");
    } else {
        var nav_menu = document.getElementById(id);
        if (nav_menu.className.indexOf("show") < 0) nav_menu.className += " show";
    }

}

function setTutorialStatus(status) {
    if (tutorial_status < TS.FINISH)
        if (status < TS.FINISH) {
            tutorial_status = status;
            saveTutorialStatus(tutorial_status, function () {
                tutorialHandler();
            });
        }

}

function saveTutorialStatus(tutorialstatus, callback) {
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");
    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "settutorialstatus",
        value: tutorialstatus
    };
    CallHandler("adm_get", senddata, function (res) {
        var code = parseInt(res.code);
        if (code == 100) {
            tutorial_status = parseInt(res.message);
            callback();
        } else {

        }

    }, function (err) {
        C_showToast("튜토리얼 Status 저장에러", "" + err, function () {});
    });
}

function showTutorial(isfilter, x, y, w, h, addtag) {

    var clip_container = document.getElementById("clip_container");
    var back_filter_tag = isfilter ? "backdrop-filter: blur(3px);background-color: #14141469;" : "";
    clip_container.style = "display:block;position:absolute;width:100%;height:100%;" + back_filter_tag + "z-index:9999;clip-path: polygon(0% 0%,0% 100%,var(--windowposition-x) 100%,var(--windowposition-x) var(--windowposition-y),calc(var(--windowposition-x) + var(--windowposition-width)) var(--windowposition-y),calc(var(--windowposition-x) + var(--windowposition-width)) calc(var(--windowposition-y) + var(--windowposition-height)),var(--windowposition-x) calc(var(--windowposition-y) + var(--windowposition-height)),var(--windowposition-x) 100%,100% 100%,100% 0%);--windowposition-x: " + x + "px;--windowposition-y: " + y + "px;--windowposition-height: " + h + "px;--windowposition-width: " + w + "px;";

    clip_container.innerHTML = "";
    clip_container.innerHTML += addtag;
    var sidemainnav_bottom = document.getElementById("sidemainnav_bottom");
    var sheight = document.body.scrollHeight + parseInt(sidemainnav_bottom.style.height);
    clip_container.style.height = sheight + "px";
    if (addtag.indexOf("tutorial_pigarrow") >= 0)
        animPigArrow();
}

function hideTutorial() {
    var clip_container = document.getElementById("clip_container");
    clip_container.style.display = "none";
}

function initVat(centercode) {
    var _data = {
        "type": "getvat", // group or center or auth
        "centercode": centercode,
    };
    CallHandler("getdata", _data, function (res) {
        code = parseInt(res.code);
        if (code == 100) {
            global_vat = res.message;
            global_centersetting = res.centersetting ? res.centersetting : {};
            if(global_centersetting.center_holiday)initCustomHoliday(global_centersetting.center_holiday);

        }

    }, function (err) {
        //        alertMsg("네트워크 에러 initVat");

    });
}
