function isallindata(alllist, arr) {
    var cnt = 0;
    if (alllist && arr)
        for (var i = 0; i < alllist.length; i++) {
            for (var j = 0; j < arr.length; j++) {
                if (alllist[i] == arr[j]) {
                    cnt++;
                }
            }
        }
    clog(" cnt " + cnt + " arr " + arr.length);
    if (cnt >= arr.length)
        return true;
    else
        return false;
}

