function loadJSON(filePath, callback) {
    fetch(filePath)
        .then(response => {
            if (!response.ok) {
                throw new Error("HTTP error " + response.status);
            }
            return response.json();
        })
        .then(data => {
            callback(null, data); // 성공 시 callback에 데이터 전달
        })
        .catch(error => {
            callback(error, null); // 실패 시 callback에 에러 전달
        });
}

