function getDateToStr(yy, _mm, _dd, h, m, s) {
    var a = _mm + 1;

    var mm = a < 10 ? "0" + a : a;
    var dd = _dd < 10 ? "0" + _dd : _dd;

    var hh = "";
    var mmm = "";
    var ss = "";

    if (!h)
        hh = "00";
    else
        hh = h < 10 ? "0" + h : h;

    if (!m)
        mmm = "00";
    else
        mmm = m < 10 ? "0" + m : m;

    if (!s)
        ss = "00";
    else
        ss = s < 10 ? "0" + s : s;


    return yy + "-" + mm + "-" + dd + " " + hh + ":" + mmm + ":" + ss;
}

function getYMDH(yy, _mm, _dd, h) {

    var m = _mm + "";
    var d = _dd + "";


    var mm = m.length < 2 ? "0" + m : m;
    var dd = d.length < 2 ? "0" + d : d;

    var hh = "";
    var mmm = "";
    var ss = "";

    if (!h)
        hh = "00";
    else
        hh = h.length < 2 ? "0" + h : h;


    return yy + "-" + mm + "-" + dd + " " + hh + ":00:00";
    //    new Date(yy,mm,dd,hh,mmm,ss).toISOString();
}

function stringGetYear(str) {
    var now = new Date(str);
    return now.getFullYear();
}

function stringGetMonth(str) {
    var now = new Date(str);
    var month = now.getMonth() + 1;
    if (month < 10) month = "0" + month;
    return month;
}

function stringGetDay(str) {
    var now = new Date(str);
    var day = now.getDate();
    if (day < 10) day = "0" + day;
    return day;
}

function stringGetHour(str) {
    var now = new Date(str);
    var hour = now.getHours();

    return hour;
}

function stringGetMin(str) {
    var now = new Date(str);
    var min = now.getMinutes();

    return min;
}

function getToday(mdate) {
    if (!mdate)
        var now = new Date();
    else
        var now = mdate;
    var year = now.getFullYear();
    var month = now.getMonth() + 1;
    if (month < 10) month = "0" + month;
    var day = now.getDate();
    if (day < 10) day = "0" + day;
    var today = year + "-" + month + "-" + day;
    return today;
}

function isThisMonth(couponid, year, month) {
    var coupon_year = stringGetYear(couponid);
    var coupon_month = stringGetMonth(couponid);

    //    var now = new Date();
    //    var year = now.getFullYear();
    //    var month = now.getMonth() + 1;
    if (parseInt(coupon_year) == year && parseInt(coupon_month) == month)
        return true;
    else return false;
}

//삭제된 쿠폰은 체크하지 않음
function getCoupons(info, type) {
    var used_coupons = new Array();
    var using_coupons = new Array();
    var after_coupons = new Array();
    var all_coupons = new Array();
    var membership = null;
    var reservation = null;

    if (info.mem_membership && info.mem_membership != null && info.mem_membership.length > 0)
        membership = JSON.parse(info.mem_membership);
    if (info.mem_reservation && info.mem_reservation != null && info.mem_reservation.length > 0)
        reservation = JSON.parse(info.mem_reservation);

    if (type == "using") {
        if (membership)
            for (var a = 0; a < membership.length; a++) {
                var isuse = C_isUsingCoupon(membership[a]);
                if (isuse == 1 || isuse == 2) {
                    using_coupons.push(membership[a]);
                }
            }

        if (reservation)
            for (var a = 0; a < reservation.length; a++) {
                var isuse = C_isUsingCoupon(reservation[a]);
                if (isuse == 1 || isuse == 2) {
                    using_coupons.push(reservation[a]);
                }
            }
    } else if (type == "used") {
        if (membership)
            for (var a = 0; a < membership.length; a++) {
                var isuse = C_isUsingCoupon(membership[a]);
                if (isuse == 0) {
                    used_coupons.push(membership[a]);
                }
            }

        if (reservation)
            for (var a = 0; a < reservation.length; a++) {
                var isuse = C_isUsingCoupon(reservation[a]);
                if (isuse == 0) {
                    used_coupons.push(reservation[a]);
                }
            }
    } else if (type == "after") {
        if (membership)
            for (var a = 0; a < membership.length; a++) {
                var isuse = C_isUsingCoupon(membership[a]);
                if (isuse == 2) {
                    after_coupons.push(membership[a]);
                }
            }

        if (reservation)
            for (var a = 0; a < reservation.length; a++) {
                var isuse = C_isUsingCoupon(reservation[a]);
                if (isuse == 2) {
                    using_coupons.push(reservation[a]);
                }
            }
    } else if (type == "all") {

        if (membership)
            for (var a = 0; a < membership.length; a++) {
                all_coupons.push(membership[a]);
            }

        if (reservation)
            for (var a = 0; a < reservation.length; a++) {
                all_coupons.push(reservation[a]);
            }
    }



    if (type == "using") {
        return using_coupons;
    } else if (type == "used") {
        return used_coupons;
    } else if (type == "all") {
        return all_coupons;
    } else
        return after_coupons;
}

function setJSONStringToParamString(json) {
    if (!json) {
        return "";
    }
    var v = JSON.stringify(json);
    //    v = v.replaceAll('"', '\\"');
    v = v.replace(/"/g, '\\"');
    //    v = v.replaceAll('"', "'");
    return v;
}
