//회원정보에서 수정할수 있는 권한이 1개라도 있다면
function isSettingUserInfo() {
    var flg = false;
    if (permission_list)
        for (var i = 0; i < permission_list.length; i++) {
            var num = parseInt(permission_list[i]);
            if (num >= 100) {
                flg = true;
                break;
            }
        }
    return flg;
}

function isPermission(checknum) {
    var flg = false;
    if (permission_list) {
        for (var i = 0; i < permission_list.length; i++) {
            var num = parseInt(permission_list[i]);
            if (num == checknum) {
                flg = true;
                break;
            }
        }
    } else {
        if (auth >= AUTH_OPERATOR) flg = true;
    }

    return flg;
}

function findInfo(key) {
    var info = null;
    for (var i = 0; i < global_userinfos.length; i++) {
        if (global_userinfos[i].key == key) {
            info = global_userinfos[i].info;
            break;
        }
    }
    return info;
}

