function getUserInfoString(info) {
    var str = "";
    str += "* mem_uid : " + info.mem_uid + "<br>";
    str += "* mem_userid : " + info.mem_userid + "<br>";
    str += "* mem_username : " + info.mem_username + "<br>";
    str += "* mem_pass : " + info.mem_pass + "<br>";
    var membership = info.mem_membership ? JSON.parse(info.mem_membership) : "";
    var reservation = info.mem_reservation ? JSON.parse(info.mem_reservation) : "";
    var teacher_reservation = info.mem_teacher_reservation != "" && info.mem_teacher_reservation != "null" ? JSON.parse(info.mem_teacher_reservation) : "";
    var newlockers = info.mem_newlockers != "" && info.mem_newlockers != "null" ? JSON.parse(info.mem_newlockers) : "";

    str += "* mem_membership : " + setJSONStringToParamString(membership) + "<br>";
    str += "* mem_reservation : " + setJSONStringToParamString(reservation) + "<br>";
    if (teacher_reservation != "") str += "* mem_teacher_reservation : " + setJSONStringToParamString(teacher_reservation) + "<br>";
    str += "* mem_starttime : " + info.mem_starttime + "<br>";
    str += "* mem_endtime : " + info.mem_endtime + "<br>";
    if (newlockers != "") str += "* mem_newlockers : " + setJSONStringToParamString(newlockers) + "<br>";
    str += "* mem_regtime : " + info.mem_regtime + "<br>";
    str += "* mem_groupcode : " + info.mem_groupcode + "<br>";
    str += "* mem_centercodes : " + info.mem_centercodes + "<br>";
    str += "* mem_fcmtoken : " + info.mem_fcmtoken + "<br>";
    str += "* mem_constructor : " + info.mem_constructor + "<br>";
    str += "* mem_other : " + info.mem_other + "<br>";

    return str;

}

