function confirm_removeptdata(removeptid, coupon_id, managerid, managername, useruid, username, userphone, stime, etime, maxcount, usecount) {

    var obj = new Object();
    obj.centercode = getData("nowcentercode");
    obj.managerid = managerid;
    obj.managername = managername;
    obj.managername = managername;
    obj.useruid = useruid;
    obj.username = username;
    obj.userphone = userphone;
    obj.starttime = stime;
    obj.endtime = etime;
    obj.maxcount = maxcount;
    obj.usecount = usecount;
    obj.removecount = parseInt(document.getElementById("pt_remaincount").value);
    obj.couponid = coupon_id;
    obj.check_removept_desc = document.getElementById("check_removept_desc").checked;
    obj.managerbirth = document.getElementById("removept_managerbirth").value;
    obj.managerphone = document.getElementById("removept_managerphone").value;

    obj.removeptid = removeptid;
    obj.removeptstatus = 2; // 1 : 신청함  2: 관리자가 승인함
    obj.note = ""; //특이사항 입력

    showModalDialog(document.body, "잔여세션 소진신청승인", obj.managername + "님이 요청한  (회원명:" + obj.username + "님)의 잔여세션(" + obj.removecount + "회) 종료 신청을 승인하시겠습니까?", "승인하기", "취소", function () {

        var _data = {
            "type": "removeptcount", // group or center or auth
            "centercode": getData("nowcentercode"),
            "value": obj
        };
        CallHandler("getdata", _data, function (res) {
            code = parseInt(res.code);
            clog("setMembership res is ", res);
            if (code == 100) {
                sendPushMessage(obj.managerid, "요청하신 (회원명:" + obj.username + "님)의 잔여세션 종료 신청이 승인되었습니다.");
                //                        alertMsg(obj.managername+"님이 요청한  (회원명:"+obj.username+"님)의 잔여세션 종료 신청을 승인하였습니다.",function(){
                hideModalDialog();
                hideModalDialog();
                hideModalDialog();
                //                        });
                loadMainDiv(33);

            } else {
                alertMsg(res.message);
            }

        }, function (err) {
            alertMsg("네트워크 에러 ");

        });


    }, function () {
        hideModalDialog();
    });
}

function remove_user(key, uid, userid, name, auth) {
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");
    var value = {
        uid: uid,
        id: userid,
        auth: auth
    }
    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "removeuser",
        value: value
    }


    var title = "※(경고)유저삭제";
    var message = name + " 님을 완전히 삭제하시겠습니까?";
    showModalDialog(document.body, title, message, "삭제하기", "취소", function () {

        CallHandler("adm_get", senddata, function (res) {
            code = parseInt(res.code);
            if (code == 100) {
                loadMainDiv(now_pageid, now_pagevalue);
                alertMsg("성곡적으로 삭제하였습니다.", function () {
                    hideModalDialog();
                    hideModalDialog();
                })
            } else {
                alertMsg(res.message, function () {
                    hideModalDialog();
                    hideModalDialog();
                });
            }


        }, function (err) {
            alertMsg("네트워크 에러 ", err);
            hideModalDialog();

        });

    }, function (err) {

        hideModalDialog();
    });

}
