var simple_mbs_coupons = null;
var simple_term_coupons = [];
var simple_count_coupons = [];
var simple_other_coupons = [];
function getBaseCoupons(centercode, callback) {

    if (centercode == null) return;
    centercode;
    var _data = {
        "type": "membership", // group or center or auth
        "mbs_centercode": centercode
    };
    //            clog("centercode is " + centercode);
    CallHandler("getdata", _data, function (res) {
        console.log("basecoupons ",res);
        var code = parseInt(res.code);
        if (code == 100) {
            simple_mbs_coupons = res.message;
            if(simple_mbs_coupons){
                 simple_term_coupons = [];
                 simple_count_coupons = [];
                 simple_other_coupons = [];
                
                for( var i = 0 ; i < simple_mbs_coupons.length; i++){
                    if(simple_mbs_coupons[i].mbs_type == TYPE_TERM)
                        simple_term_coupons.push(simple_mbs_coupons[i]);
                    else if(simple_mbs_coupons[i].mbs_type == TYPE_PT)
                        simple_count_coupons.push(simple_mbs_coupons[i]);
                    else if(simple_mbs_coupons[i].mbs_type == TYPE_OTHER)
                        simple_other_coupons.push(simple_mbs_coupons[i]);                
                }
            }
            
        }
        
        callback(res);
    }, function (err) {
        alertMsg("네트워크 에러 ");

    });

}

