var loc_alllocker = null;
var loc_selected_locker_id = null;
var loc_userdatas = null;
var loc_userdata = null;
var locker_type_userid = ""; //유저를 지정하면 자동으로 검색한다.
var locker_type_user_starttime = ""; //시작일을 지정하면 자동으로 설정한다.
var locker_type_user_endtime = ""; //종료일을 지정하면 자동으로 설정한다.
//오늘날짜 비교하여 날짜가 지났는지 안지났는지 아니면 시작하지 않았는지  현재사용중 1 : 이미 지남 0 : 아직 시작전 : 2
function C_DateOverCheck(starttime, endtime) {
    if (!starttime || !endtime) {
        return 0;
    }
    var date = new Date();
    var now_timestamp = date.getTime();
    var start = new Date(starttime);
    var start_timestamp = start.getTime();
    var end = new Date(endtime);
    var end_timestamp = end.getTime();
    if (now_timestamp > start_timestamp && now_timestamp < end_timestamp) {
        //        clog("현재 운동중인 쿠폰");
        return 1;
    } else if (now_timestamp < start_timestamp) {
        //        clog("운동 시작할 예정인 쿠폰");
        return 2;
    } else {
        //        clog("운동끝난 쿠폰");
        return -1;
    }
}

function getNowDateTime() {
    var now = new Date();
    now.setMinutes(now.getMinutes() - now.getTimezoneOffset());
    var startdatetime = now.toISOString().slice(0, 16);
    //    var startdatetime = now.toISOString();
    return startdatetime;
}
//0 : 오늘날 -1 : 오늘안지남 , 1: 오늘이전
function isToday(end) {
    var start_date = new Date();
    var end_date = new Date(end);
    var gap = start_date.getTime() - end_date.getTime();
    var dday = Math.floor(gap / (1000 * 60 * 60 * 24)) * -1;
    if (dday == 0) return 0;
    else if (dday > 0) return -1;
    else return 1;
}

function getDay(start, end) {

    if (start.length <= 10) start += " 00:00:00";
    if (end.length <= 10) end += " 00:00:00";
    var start_date = new Date(start);
    var end_date = new Date(end);
    var gap = start_date.getTime() - end_date.getTime();
    var dday = Math.floor(gap / (1000 * 60 * 60 * 24)) * -1;
    return dday;
}

function getDDay(end) {
//    var today = new Date();
//    console.log("getDDay today "+today+" end "+end+" dday "+getDay(today, end));
//    return getDay(today, end);
    
    var str_today = getToday();
    var str_end = end.substr(0,10);
    
    var today_timestamp = new Date(str_today).getTime();
    var end_timestamp = new Date(str_end).getTime();
    var gabday = parseInt((end_timestamp - today_timestamp)/86400/1000);
//    console.log("gabday "+gabday);
    return gabday;
}


function compareDay(start, end) {
    return getDay(start, end);
}
//num = min
function nextMin(str_date, num) {
    var add_tiemstamp = 1000*60*num;
    
    
    var date = str_date.indexOf("Z") >= 0 ? new Date(str_date) : new Date(str_date+"Z");
    return new Date(date.getTime() + add_tiemstamp).toISOString().replace('T', ' ').slice(0, -5);
    
}
//num = hour
function nextHour(str_date, num) {
    var add_tiemstamp = 1000*60*60*num;
    
    var date = str_date.indexOf("Z") >= 0 ? new Date(str_date) : new Date(str_date+"Z");
    return new Date(date.getTime() + add_tiemstamp).toISOString().replace('T', ' ').slice(0, -5);
}

//format yyyy-mm-dd
function nextDay(today, num) {
    // ex) 2019-12-10 
    let d = new Date(today) // 2019-12-10T00:00:00.000Z 
    d.setDate(d.getDate() + parseInt(num));
    //    clog("d getdate ",d.getDate());
    return getToday(d);
}

function nextMonth(today, num) {
    //     let d = new Date(today) // 2019-12-10T00:00:00.000Z 
    //    d.setMinutes(d.getMinutes()-1);
    //    d.setDate(d.getDate() -1);
    //    d.setMonth(d.getMonth() +  parseInt(num));
    //    

    // ex) 2019-12-10 
    let d = new Date(today) // 2019-12-10T00:00:00.000Z 
    d.setMonth(d.getMonth() + parseInt(num));
    d.setSeconds(d.getSeconds() - 1);
    d.setDate(d.getDate() - 1);
    clog("d nextMonth ", d);
    return getToday(d);
}

function nextYear(today, num) {
    // ex) 2019-12-10 
    let d = new Date(today) // 2019-12-10T00:00:00.000Z 
    d.setFullYear(d.getFullYear() + parseInt(num));
    clog("d getdate ", d.getFullYear());
    return getToday(d);
}

function dateFormat(date) {
    if (!date) date = new Date();
    let month = date.getMonth() + 1;
    let day = date.getDate();
    let hour = date.getHours();
    let minute = date.getMinutes();
    let second = date.getSeconds();

    month = month >= 10 ? month : '0' + month;
    day = day >= 10 ? day : '0' + day;
    hour = hour >= 10 ? hour : '0' + hour;
    minute = minute >= 10 ? minute : '0' + minute;
    second = second >= 10 ? second : '0' + second;

    return date.getFullYear() + '-' + month + '-' + day + ' ' + hour + ':' + minute + ':' + second;
}

function getDateFullFormat(strdate) {
    var date = new Date(strdate);
    let year = date.getFullYear();
    let month = date.getMonth() + 1;
    let day = date.getDate();
    let hour = date.getHours();
    let minute = date.getMinutes();
    let second = date.getSeconds();

    month = month >= 10 ? month : '0' + month;
    day = day >= 10 ? day : '0' + day;
    hour = hour >= 10 ? hour : '0' + hour;
    minute = minute >= 10 ? minute : '0' + minute;
    second = second >= 10 ? second : '0' + second;
    var ampm = hour > 12 ? "오후" : "오전";
    return month + "월" + day + "일" + " " + ampm + " " + hour + "시 " + minute + "분(" + year + ")";
}
