function createInputLogExcelData(username, userid, logs) {

    var titles = ["센터명", "이름", "날짜"];

    var len = logs.length;
    excel_data = [];

    if (len > 0) {
        for (var a = 0; a < len; a++) {
            excel_data.push({
                "센터명": logs[a].centername,
                "이름": username,
                "고객번호": userid,
                "날짜": logs[a].date
            });
        }
    }

}

