var before_genderidx = 0;

function onclick_locker_gender(genderidx) {
    if (before_genderidx != genderidx) {
        if (genderidx == 0) { //전체
            $("#select_locker_gender_0").show(200);
            $("#select_locker_gender_1").hide(100);
            $("#select_locker_gender_2").hide(100);
            $(".lockerclass_title_M").show(0);
            $(".lockerclass_body_M").show(0);
            $(".lockerclass_title_F").show(0);
            $(".lockerclass_body_F").show(0);

        } else if (genderidx == 1) { //남자라커
            $("#select_locker_gender_0").hide(100);
            $("#select_locker_gender_1").show(200);
            $("#select_locker_gender_2").hide(100);
            $(".lockerclass_title_M").show(0);
            $(".lockerclass_body_M").show(0);
            $(".lockerclass_title_F").hide(0);
            $(".lockerclass_body_F").hide(0);
        } else { // 여자라커
            $("#select_locker_gender_0").hide(100);
            $("#select_locker_gender_1").hide(100);
            $("#select_locker_gender_2").show(200);
            $(".lockerclass_title_M").hide(0);
            $(".lockerclass_body_M").hide(0);
            $(".lockerclass_title_F").show(0);
            $(".lockerclass_body_F").show(0);
        }
        before_genderidx = genderidx;
    }
}



