function getCouponsSelectBoxOptionsTag(allcoupons, coupon_mbsidx, coupon_mbstype, ishideprice) {
    var temp_options = "<option >회원권을 선택하세요</option>";
    for (var i = 0; i < allcoupons.length; i++) {
        if (coupon_mbstype == allcoupons[i]["mbs_type"]) {
            var selected = coupon_mbsidx == allcoupons[i]["mbs_idx"] ? "selected" : "";
            if (ishideprice)
                temp_options += "<option value='" + allcoupons[i]["mbs_idx"] + "' " + selected + ">" + allcoupons[i]["mbs_name"] + "</option>";
            else
                temp_options += "<option value='" + allcoupons[i]["mbs_idx"] + "' " + selected + ">" + allcoupons[i]["mbs_name"] + " " + TXT_WON + CommaString(allcoupons[i]["mbs_price"]) + "</option>";
        }
    }
    return temp_options;

}

//neel구분  결제목록에서 클릭
function clickDetailPaymentListButton(pm_coupontype, btntype, pm_date) {

    var isview = btntype == "view" ? true : false;
    if(btntype == "change" || btntype == "change_notpay" || btntype == "view" ){
        //pm_coupontype : 쿠폰타입 T : 기간제 , G : 그룹 , C : 횟수제 , U : 알수없음, L : 라커만 , TL : 기간제 + 라커 , R:환불 , S: 양도, M : 미수금환불, GA : GX횟수 기간추가	
        switch (pm_coupontype) {
            case "BASE": // 최초 회원권이다. 결제내역이 있을수도 없을수도 있다.
            case "T": // 기간제 회원권
            case "G": // 그룹 회원권 (GX)
            case "C": // 횟수제 회원권(PT)
                    nShowBaseCoupon(pm_date,false,isview,btntype);
                break;
            case "R": // 환불
                nShowRefundCoupon(pm_date,false,true);

                break;
            case "S": // 양도
                nShowBaseCoupon(pm_date,false,false,btntype);
                break;
            case "M": // 미수금환불
                    nShowGetRemainPrice(pm_date,false,isview);
                break;
            case "GA": // GX횟수/ 기간 수정
                    
                    nShowAddCoupondata(pm_date,false,isview,false);
                break;
            case "UG": // 업그레이드내역 수정
                    nShowUpgradeCoupon(pm_date,false,isview);
                break;
            

        }
    }
    //삭제버튼
    else {
        //pm_coupontype : 쿠폰타입 T : 기간제 , G : 그룹 , C : 횟수제 , U : 알수없음, L : 라커만 , TL : 기간제 + 라커 , R:환불 , S: 양도, M : 미수금환불, GA : GX횟수 기간추가	
        switch (pm_coupontype) {
            case "BASE": // 최초 회원권이다. 결제내역이 있을수도 없을수도 있다.
                break;
            case "T": // 기간제 회원권
            case "G": // 그룹 회원권 (GX)
            case "C": // 횟수제 회원권(PT)
//                    nDeleteBaseCoupon(pm_date);
                nDeleteAddCouponData(pm_date);
                break;
            case "R": // 환불내역을 삭제해서 복구한다.
                    nDeleteRefundCouponData(pm_date);
                break;
            case "S": // 양도 삭제
                
                break;
            case "M": // 미수금환불 삭제
                nDeleteGetRemainPrice(pm_date);
                break;
            case "GA": // GX횟수 기간 삭제
                    nDeleteAddCouponData(pm_date);
                break;
             case "UG": // 업그레이드내역 삭제
                    nDeleteUpgradeCouponData(pm_date);
                break;

        }
    }
    
}
