//환불내역 복구
function nDeleteRefundCouponData(pm_date){
    var useruid = click_coupondata.useruid;
    var userid = click_coupondata.userid;
    var coupon = click_coupondata.coupon;
    
    var username = click_coupondata.username;
    
    if(coupon.mbstype == TYPE_PT){
        alertMsg("PT 환불내역은 복구할 수 없습니다.");
        return;
    }
    
    var coupon = getClickCouponPaymentData("coupon");
    var payment = getClickCouponPaymentData("payment", pm_date); //기간추가한 결제내역이다.
    console.log("payment ",payment);
   
    var style = {
        bodycolor: "#ffffff",
        size: {
            width: "600px",
            height: "auto"
        }
    };
   
//    var pm_date = payment.pm_pay_remainid;
//    var pm_date = pm_date;
//    var addcountdata = getaddcountdata(coupon,pm_date);
    var style = {
        bodycolor: "#eeeeee",
        //        marginTop:"300px",
        size: {
            width: "860px",
            height: "100%"
        }
    };
    title = "<label style='font-size:36px;font-color:#3f4254;font-weight:500;'><경고>회원권 복구</label>";
    
    
    
    
    message = "'해당 환불내역 ["+coupon.mbsname+" "+TXT_WON+" "+CommaString(coupon.repay)+"]'을 복구하시겠습니까? <br> 환불한 매출내역도 삭제됩니다.";
    showModalDialog(document.body, title, message, "삭제", "취소", function () {
        sendDeleteRefuntData(useruid,coupon,payment);
    }, function(){
        hideModalDialog();
    }, style);
}

function sendDeleteRefuntData( useruid,coupon,payment){
        
          
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");

    var value = {
        "useruid": useruid,        
        "coupon": coupon,
        "payment" : payment        
    };
    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "refundcancel",
        value: value
    };

    CallHandler("adm_get", senddata, function (res) {
        var code = parseInt(res.code);
        if(code == 100){
            hideModalDialog();
            hideModalDialog();
            hideModalDialog();
            C_showToast("삭제완료", "해당 업그레이드 내역을 성공적으로 삭제하였습니다.", function () {});
            header_search(useruid);
        }else {
            alertMsg(res.message);
        }
        
    }, function (err) {
        alertMsg(err);
    });
    
}

