function nChangePrice(onchangeid){
    
    var input_nchange_baseprice = document.getElementById("input_nchange_baseprice");
    var input_nchange_card = document.getElementById("input_nchange_card");
    var input_nchange_cash = document.getElementById("input_nchange_cash");
    var input_nchange_remain = document.getElementById("input_nchange_remain");
    var input_nchange_discount = document.getElementById("input_nchange_discount");
    var txt_nchange_totalremain = document.getElementById("txt_nchange_totalremain");
    var select_nchange_paymenttype = document.getElementById("select_nchange_paymenttype");
    
    var baseprice = input_nchange_baseprice ?  parseCommaInt(input_nchange_baseprice.value) : 0;
    var card = input_nchange_card ? parseCommaInt(input_nchange_card.value) : 0;
    var cash = input_nchange_cash ? parseCommaInt(input_nchange_cash.value) : 0;
    var remain = input_nchange_remain ? parseCommaInt(input_nchange_remain.value) : 0;
    var discount = input_nchange_discount ? parseCommaInt(input_nchange_discount.value) : 0;
    var total_remain = txt_nchange_totalremain ? parseCommaInt(txt_nchange_totalremain.innerHTML) : 0;
    switch(onchangeid){
         case "select_nchange_paymenttype": // 결제타입 카드 ,현금 , 카드+현금
            switch (select_nchange_paymenttype.value) {
                case "1": //카드
                    if(input_nchange_card)input_nchange_card.value = input_nchange_baseprice ? TXT_WON + " " + CommaString(parseCommaInt(input_nchange_baseprice.value)) : TXT_WON + " 0";
                    if(input_nchange_cash)input_nchange_cash.value = TXT_WON + " 0";
                    if(input_nchange_remain)input_nchange_remain.value = TXT_WON + " 0";
                    if(input_nchange_discount)input_nchange_discount.value = TXT_WON + " 0";
                    if(txt_nchange_totalremain)txt_nchange_totalremain.innerHTML = input_nchange_baseprice ? TXT_WON + " " + CommaString(parseCommaInt(input_nchange_baseprice.value)) : TXT_WON + " 0";
                    break;
                case "2": //현금
                    if(input_nchange_card)input_nchange_card.value = TXT_WON + " 0";
                    if(input_nchange_cash)input_nchange_cash.value = input_nchange_baseprice ? TXT_WON + " " + CommaString(parseCommaInt(input_nchange_baseprice.value)) : TXT_WON + " 0";
                    if(input_nchange_remain)input_nchange_remain.value = TXT_WON + " 0";
                    if(input_nchange_discount)input_nchange_discount.value = TXT_WON + " 0";
                    if(txt_nchange_totalremain)txt_nchange_totalremain.innerHTML = input_nchange_baseprice ? TXT_WON + " " + CommaString(parseCommaInt(input_nchange_baseprice.value)) : TXT_WON + " 0";
                    break;
                case "4": //카드+현금
                    break;
                default:
                    if(input_nchange_card)input_nchange_card.value = TXT_WON + " 0";
                    if(input_nchange_cash)input_nchange_cash.value = TXT_WON + " 0";
                    if(input_nchange_remain)input_nchange_remain.value = TXT_WON + " 0";
                    if(input_nchange_discount)input_nchange_discount.value = TXT_WON + " 0";
                    if(txt_nchange_totalremain)txt_nchange_totalremain.innerHTML = TXT_WON + " 0";
                    break;

            }

            
            break;
         case "input_nchange_baseprice": //회원권 금액
            if(input_nchange_baseprice)input_nchange_baseprice.value = TXT_WON + " "+CommaString(baseprice);
            if(select_nchange_paymenttype)select_nchange_paymenttype.value = "";
            if(input_nchange_card)input_nchange_card.value = TXT_WON + " 0";
            if(input_nchange_cash)input_nchange_cash.value = TXT_WON + " 0";
            if(input_nchange_remain)input_nchange_remain.value = TXT_WON + " 0";
            if(input_nchange_discount)input_nchange_discount.value = TXT_WON + " 0";
            if(txt_nchange_totalremain)txt_nchange_totalremain.innerHTML = TXT_WON + " 0";
            break;
        case "input_nchange_card":
        case "input_nchange_cash":
        case "input_nchange_remain":
        case "input_nchange_discount":
           
            var price = calcullatePrice(onchangeid, baseprice, card, cash, remain, discount);
            
            if (isNaN(price.card)) price.card = 0;
            if (isNaN(price.cash)) price.cash = 0;
            if (isNaN(price.remain)) price.remain = 0;
            if (isNaN(price.discount)) price.discount = 0;
            if (isNaN(price.total_remain)) price.total_remain = 0;

            if(input_nchange_card)input_nchange_card.value = TXT_WON + " " + CommaString(price.card);
            if(input_nchange_cash)input_nchange_cash.value = TXT_WON + " " + CommaString(price.cash);
            if(input_nchange_remain)input_nchange_remain.value = TXT_WON + " " + CommaString(price.remain);
            if(input_nchange_discount)input_nchange_discount.value = TXT_WON + " " + CommaString(price.discount);            
            if(txt_nchange_totalremain){
                
                txt_nchange_totalremain.innerHTML = TXT_WON + " " + CommaString(price.total_remain);
                console.log("price.total_remain ",price.total_remain);
            }
            break;            
    }
    
}
