//회원권 홀딩신청
function nShowHoldingCoupon(pm_date){
    var useruid = click_coupondata.useruid;
    var userid = click_coupondata.userid;
    var coupon = click_coupondata.coupon;
    var username = click_coupondata.username;
    
    var coupon = getClickCouponPaymentData("coupon");
    var payment = getClickCouponPaymentData("payment", pm_date);


    var style = {
        bodycolor: "#ffffff",
        size: {
            width: "600px",
            height: "auto"
        }
    };
    
    
    var coupon_usecount = coupon.usecount ? parseInt(coupon.usecount) : 0;
    var coupon_name = coupon.mbstype == TYPE_PT ? "PT "+coupon.mbsmaxcount+"회" : coupon.mbsname; 
    if(coupon.mbstype == TYPE_GX)coupon_name = coupon.mbsname+" "+getGXCouponUseCount(useruid+"_"+coupon.id, coupon_usecount)+"회 이용";
    var coupon_price = coupon.remain_price && coupon.remain_price.total_remain ? TXT_WON+" "+CommaString(getTotalCouponPrice(coupon)) : TXT_WON+" "+CommaString(coupon.mbsprice);
    
    var title_tag = "<label style='color:#f1416c'>홀딩기간을 선택하세요.</label>";
    var dash_tag1 = "<label>"+coupon_name+" : "+coupon_price+"</label>";
    var dash_tag2 = "<label>기간 : "+coupon.starttime.substr(0,10)+" ~ "+getTotalEndtime(coupon).substr(0,10)+"</label>";
    
    var coupon_startendtime = coupon.starttime.substr(0,10)+" ~ "+getTotalEndtime(coupon).substr(0,10);
    
    var table_tag = "<table style='width:100%;height:auto'>" +
                        "<tr>" +
                            "<td style='border-bottom:1px solid #eff2f5;width:140px;height:65px;background-color:#f5f6f8;padding-left:30px;font-size:15px;font-weight:500;border:1px solid #eff2f5'>" +
                                "신청일자" +
                            "</td>" +
                            "<td  style='border-top:1px solid #eff2f5;border-bottom:1px solid #eff2f5;'>" +
                                "<input type = 'date' class='fmont' id='input_refund_date' style='width:295px;height:45px;border:0px;border-radius:5px;background-color:#f5f8fa;margin-left:30px;padding-left:30px;padding-right:15px;font-weight:400;font-size:14px' value='"+getToday()+"'>"+
                            "</td>" +
                        "</tr>" +
                        "<tr>" +
                            "<td style='border-bottom:1px solid #eff2f5;width:140px;height:65px;background-color:#f5f6f8;padding-left:30px;font-size:15px;font-weight:500;border:1px solid #eff2f5'>" +
                                "홀딩기간" +
                            "</td>" +
                            "<td  style='border-top:1px solid #eff2f5;border-bottom:1px solid #eff2f5;'>" +
                               
                                 "<span><input type = 'date' class='fmont' id='rq_holding_starttime' onchange='onChangeRQHoldingday(\"rq_holding_starttime\", \""+coupon.starttime+"\", \""+getTotalEndtime(coupon)+"\")' style='width:109px;height:45px;border:0px;border-radius:5px;background-color:#f5f8fa;margin-left:30px;padding-left:5px;font-weight:400;font-size:14px' value='"+getToday()+"'></span>"+
                                 "<span><input type = 'date' class='fmont' id='rq_holding_endtime' onchange='onChangeRQHoldingday(\"rq_holding_endtime\", \""+coupon.starttime+"\", \""+getTotalEndtime(coupon)+"\")' style='width:109px;height:45px;border:0px;border-radius:5px;background-color:#f5f8fa;margin-left:5px;padding-left:5px;font-weight:400;font-size:14px' value=''></span>"+
                                 "<span><input type='number' class='fmont'  id='input_holding_addday'  onfocus='this.select()' onkeyup='onChangeRQHoldingday(\"input_holding_addday\", \""+coupon.starttime+"\", \""+getTotalEndtime(coupon)+"\")'style='width:30px;height:45px;border:0px;border-radius:5px;background-color:#f5f8fa;margin-left:5px;font-weight:400;font-size:14px;text-align:center' value='0'><text style='font-size:13px;'>일추가</text></span>"+
                
                            "</td>" +
                            
                        "</tr>" +
                        "<tr>" +
                            "<td style='border-bottom:1px solid #eff2f5;width:140px;height:65px;background-color:#f5f6f8;padding-left:30px;font-size:15px;font-weight:500;'>" +
                                "변경된 유효기간" +
                            "</td>" +
                            "<td  style='border-bottom:1px solid #eff2f5;'>" +
                                "<input class='fmont' id='input_holding_changed_desc' style='width:295px;height:45px;border:0px;border-radius:5px;background-color:#e9e9e9;margin-left:30px;padding-left:30px;font-weight:400;font-size:14px'  value='"+coupon_startendtime+"' disabled>"+
                            "</td>" +
                        "</tr>" +
                        "<tr>" +
                            "<td style='border-bottom:1px solid #eff2f5;width:14px;height:65px;background-color:#f5f6f8;padding-left:30px;font-size:15px;font-weight:500;border:1px solid #eff2f5'>" +
                                "특이사항" +
                            "</td>" +
                            "<td  style='border-top:1px solid #eff2f5;border-bottom:1px solid #eff2f5;'>" +
                                "<input class='fmont' id='rq_holding_desc' onfocus='this.select()'  style='width:295px;height:45px;border:0px;border-radius:5px;background-color:#f5f8fa;margin-left:30px;padding-left:30px;font-weight:400;font-size:14px'  value=''>"+
                            "</td>" +
                        "</tr>" +
                "</table>";
                
    
    var message_tag = getDetailSubMessageTag(title_tag,dash_tag1,dash_tag2,table_tag);
    
    var title = "[" + username + "] 회원권 홀딩";
    showModalDialog(document.body, title, message_tag, "홀딩신청", "취소", function () {
        var holdingstarttime = document.getElementById("rq_holding_starttime").value;
        var holdingendtime = document.getElementById("rq_holding_endtime").value;
        var holding_desc = document.getElementById("rq_holding_desc").value;
        
        if (!holdingstarttime || !holdingendtime) {
            alertMsg("홀딩 시작일과 종료일을 모두 선택해 주세요");
            return;
        }
        if (getDay(holdingstarttime, holdingendtime) < 0) {
            alertMsg("시작일보다 종료일이 커야합니다.");
            return;
        }
        holdingstarttime = holdingstarttime.length < 12 ? holdingstarttime +" 00:00:00" : holdingstarttime;
        holdingendtime = holdingendtime.length < 12 ? holdingendtime + " 23:59:59" : holdingendtime;
        requestHolding(useruid, userid, coupon.id, coupon.starttime, coupon.endtime, holdingstarttime, holdingendtime, holding_desc);

            

    }, function () {
        hideModalDialog();

    }, style);
}
function onChangeRQHoldingday(changedid, coupon_starttime, coupon_endtime){
    var rq_holding_starttime = document.getElementById("rq_holding_starttime"); //홀딩시작일
    var rq_holding_endtime = document.getElementById("rq_holding_endtime"); // 홀딩 종료일
    var input_holding_addday = document.getElementById("input_holding_addday"); // 홀딩일수
    var input_holding_changed_desc = document.getElementById("input_holding_changed_desc"); //변경된 회원권 유효기간
    
    if(rq_holding_starttime.value && getDay(rq_holding_starttime.value, coupon_starttime) > 0){
        rq_holding_starttime.value = coupon_starttime.substr(0,10);
        alertMsg("홀딩시작일은 회원권 기간내에서만 설정 가능합니다.");
        return;
    }
    else if(rq_holding_endtime.value && getDay(rq_holding_endtime.value, coupon_endtime) < 0){
        rq_holding_endtime.value = coupon_endtime.substr(0,10);
        alertMsg("홀딩종료일은 회원권 기간내에서만 설정 가능합니다.");
        return;
    }else if(rq_holding_starttime.value && rq_holding_endtime.value && getDay(rq_holding_starttime.value, rq_holding_endtime) < 0){
        if(changedid == "rq_holding_starttime")
            rq_holding_starttime.value = coupon_starttime.substr(0,10);
        else if(changedid == "rq_holding_endtime")
            rq_holding_endtime.value = coupon_endtime.substr(0,10);
        
        alertMsg("홀딩 종료일은 홀딩 시작일보다 커야합니다.");
        return;
    }
    if(changedid == "rq_holding_starttime" || changedid == "rq_holding_endtime"){
       if(rq_holding_starttime.value && rq_holding_endtime.value){
           input_holding_addday.value = getDay(rq_holding_starttime.value,rq_holding_endtime.value)+1;
       } 
    }
    
    if(!input_holding_addday.value)
            input_holding_addday.value = "0";
    if(parseInt(input_holding_addday.value) < 1){
        rq_holding_endtime.value = "";
        input_holding_changed_desc.value = coupon_starttime.substr(0,10)+" ~ "+coupon_endtime.substr(0,10);
    }
    else if(rq_holding_starttime && rq_holding_endtime && input_holding_addday.value){
    
        var addday = parseInt(input_holding_addday.value);
        rq_holding_endtime.value = nextDay(rq_holding_starttime.value, addday-1);

        var last_endtime = nextDay(coupon_endtime.substr(0,10),addday);
        input_holding_changed_desc.value = coupon_starttime.substr(0,10)+" ~ "+last_endtime.substr(0,10); //
    }
    
}
