function sendGetRemainPrice(pm_date,pm_idx,isnew,pm_coupontype,locker,other){
  
    var useruid = click_coupondata.useruid;
    var userid = click_coupondata.userid;
    var coupon = click_coupondata.coupon;
    var username = click_coupondata.username;
    
    var input_nchange_paymentdate = document.getElementById("input_nchange_paymentdate");
    var input_nchange_note = document.getElementById("input_nchange_note");
    var input_nchange_baseprice = document.getElementById("input_nchange_baseprice");
    var select_nchange_paymenttype = document.getElementById("select_nchange_paymenttype");
    var input_nchange_card = document.getElementById("input_nchange_card");
    var input_nchange_cash = document.getElementById("input_nchange_cash");
    var input_nchange_remain = document.getElementById("input_nchange_remain");
    var txt_nchange_totalremain = document.getElementById("txt_nchange_totalremain");
    var input_nchange_cardnumber = document.getElementById("input_nchange_cardnumber");
    
    var baseprice = parseCommaInt(input_nchange_baseprice.value);
    var card = parseCommaInt(input_nchange_card.value);
    var cash = parseCommaInt(input_nchange_cash.value);
    var remain = parseCommaInt(input_nchange_remain.value);
    var price = {
        "card":card,
        "cash":cash,
        "remain":remain,
        "discount":0,
        "total":card+cash+remain,
        "total_remain":card+cash
    }
    var lockerdata = locker && locker.data ? locker.data : null;
    if(lockerdata && lockerdata.price){
        lockerdata.price = price;
    }
    var otherdata = other && other.data ? other.data : null;
    if(otherdata && otherdata.price){
        otherdata.price = price;
    }
    
        
        
         
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");

//    if(locker && locker.payment){
//        var payment = locker.payment;    
//    }else if(other && other.data){
//        var payment = other.payment;            
//    }else {
//        var payment = getPaymentInList(pm_idx);    
//    }
    
    var isnewnum = isnew ? 1 : 0;
    var value = {
        "isnew" : isnewnum,
        "useruid": click_coupondata.useruid,
        "paymentdate": input_nchange_paymentdate.value,     
        "coupon": click_coupondata.coupon,
        "lockerdata": lockerdata,
        "otherdata": otherdata,
        "pmidx": pm_idx,
        "pm_date" : pm_date,
        "pm_coupontype": pm_coupontype,
        "note" : input_nchange_note.value,
        "paymenttype":select_nchange_paymenttype.value,
        "cardnumber":input_nchange_cardnumber.value,
        "price" : price
    };
    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "sendgetremainprice",
        value: value
    };

    if(baseprice > 0 && !select_nchange_paymenttype.value){
        alertMsg("금액이 0원이상일때는 결제방법을 선택해 주세요");
        return;
    }
    CallHandler("adm_get", senddata, function (res) {
        var code = parseInt(res.code);
        if(code == 100){
            hideModalDialog();
            hideModalDialog();
            hideModalDialog();
            C_showToast("미수금회수 완료", "성공적으로 미수금을 회수하였습니다.", function () {});
            header_search(useruid);
        }else {
            alertMsg(res.message);
        }
        
    }, function (err) {
        alertMsg(err);
    });
    
    

}
