function sendBaseCouponUpgrade(isnew,pm_date, pm_idx){
   
    var useruid = click_coupondata.useruid;
    var userid = click_coupondata.userid;
    var coupon = click_coupondata.coupon;
    var username = click_coupondata.username;
    
    var input_nchange_beforecoupon = document.getElementById("input_nchange_beforecoupon");
    var select_nchange_basecoupon = document.getElementById("select_nchange_basecoupon");
    var input_nchange_paymentdate = document.getElementById("input_nchange_paymentdate");
    var input_nchange_mbsmaxcount = document.getElementById("input_nchange_mbsmaxcount");
    var input_nchange_maxholdingday = document.getElementById("input_nchange_maxholdingday");
    var input_nchange_starttime = document.getElementById("input_nchange_starttime");
    var input_nchange_endtime = document.getElementById("input_nchange_endtime");
    var input_nchange_note = document.getElementById("input_nchange_note");
    var input_nchange_baseprice = document.getElementById("input_nchange_baseprice");
    var select_nchange_paymenttype = document.getElementById("select_nchange_paymenttype");
    var input_nchange_card = document.getElementById("input_nchange_card");
    var input_nchange_cash = document.getElementById("input_nchange_cash");
    var input_nchange_remain = document.getElementById("input_nchange_remain");
    var txt_nchange_totalremain = document.getElementById("txt_nchange_totalremain");
    var input_nchange_cardnumber = document.getElementById("input_nchange_cardnumber");
    
    var baseprice = parseCommaInt(input_nchange_baseprice.value);
    var card = parseCommaInt(input_nchange_card.value);
    var cash = parseCommaInt(input_nchange_cash.value);
    var remain = parseCommaInt(input_nchange_remain.value);
    var price = {
        "card":card,
        "cash":cash,
        "remain":remain,
        "discount":0,
        "total":card+cash+remain,
        "total_remain":card+cash
    }

    var selected_basecoupon = getBaseCoupon(select_nchange_basecoupon.value);
    coupon.mbsidx = selected_basecoupon.mbs_idx;
    coupon.mbsname = selected_basecoupon.mbs_name;
    coupon.mbsprice = selected_basecoupon.mbs_price;
    coupon.mbsmonth = selected_basecoupon.mbs_month;
    coupon.mbsmaxholdingday = input_nchange_maxholdingday.value;
    coupon.mbsmaxchangestarttime = selected_basecoupon.mbs_max_change_starttime;
    coupon.mbsmaxcount = input_nchange_mbsmaxcount.value;
    coupon.starttime = input_nchange_starttime.value;
    coupon.endtime = input_nchange_endtime.value;
    
    
    
         
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");
    
    var payment = getPaymentInList(pm_idx);
    var isnewnum = isnew ? 1 : 0;
    var value = {
        "isnew" : isnewnum,
        "useruid": click_coupondata.useruid,
        "paymentdate": input_nchange_paymentdate.value,     
        "coupon": coupon,
        "pmidx": pm_idx,
        "pm_date" : pm_date,
        "addcount" : 0,
        "addday" : 0,
        "note" : input_nchange_note.value,
        "paymenttype":select_nchange_paymenttype.value,
        "cardnumber":input_nchange_cardnumber.value,
        "price" : price,
        "beforecoupon":JSON.parse(input_nchange_beforecoupon.value)
    };
    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "couponupgrade",
        value: value
    };

    if(baseprice > 0 && !select_nchange_paymenttype.value){
        alertMsg("금액이 0원이상일때는 결제방법을 선택해 주세요");
        return;
    }
    CallHandler("adm_get", senddata, function (res) {
        var code = parseInt(res.code);
        if(code == 100){
            hideModalDialog();
            hideModalDialog();
            hideModalDialog();
            C_showToast("수정완료", "성공적으로 수정하였습니다.", function () {});
            header_search(useruid);    
        }else {
            alertMsg(res.message);
        }
        
    }, function (err) {
        alertMsg(err);
    });
    
    

}
function showMessageList(uid){
    
//    console.log("str_alert ",str_alert);
    var alert = global_user_info.mem_uid == uid && global_user_info.mem_alert ? JSON.parse(global_user_info.mem_alert) : [];

    if(!alert){
        alertMsg("메세지 목록이 없습니다.");
        return;
    }
    
    var style = {
        bodycolor: "#eeeeee",
        size: {
            width: "75%",
            height: "100%"
        }
    };
    
    
   var title = "메세지 전송내역";
    var message = getMessageListTag(alert);
    showModalDialog(document.body, title, message, "닫기", null, function () {
        hideModalDialog();
    }, null, style);
    
}
function nShowCouponUseList(){
    var useruid = click_coupondata.useruid;
    var userid = click_coupondata.userid;
    var coupon = click_coupondata.coupon;
    var username = click_coupondata.username;
    
    var value = {
        "uid":useruid,
        "couponid":coupon.id,
        "starttime":coupon.starttime,
        "endtime":coupon.endtime
    }
    getGXCouponUseData(value ,function(res){
        var code = parseInt(res.code);
        console.log("res ",res);
        if(code == 100){
            console.log("getGXCouponUseData ", res.message);
            var style = {
                bodycolor: "#eeeeee",
                size: {
                    width: "75%",
                    height: "100%"
                }
            };
            var title = coupon.mbsname+" 예약현황";
            var message = getGXReservationTag(res.message, 0);
            showModalDialog(document.body, title, message, "닫기", null, function () {
                hideModalDialog();
            }, null, style);
            
            
        }else{
            alertMsg(res.message);
        }
         
    });
}
