//기타상품 환불하기
function setRefundOther(uid, key, value, refunddate) {
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");
    
    var input_id_repay = parseCommaInt(document.getElementById("input_id_repay").value);
    var repaytype = document.getElementById("select_id_repaytype").value;
    var input_id_repayother = document.getElementById("input_id_repayother").value;
    if (input_id_repay == 0) {
        alertMsg("환불비용은 0 원이상을 입력하세요.");
        return;
    }

    var repay_remainprice = {"card":0,"cash":0,"remain":0,"discount":0,"total":0,"total_remain":0};
    if(repaytype == 1){
        repay_remainprice.card = input_id_repay;
        repay_remainprice.total = input_id_repay;
        repay_remainprice.total_remain = input_id_repay;
    }else if(repaytype == 2){
        repay_remainprice.cash = input_id_repay;
        repay_remainprice.total = input_id_repay;
        repay_remainprice.total_remain = input_id_repay;
    }
    //    
    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "refundother",
        value: {
            "uid": uid,
            "othercoupon": value,
            "repay": input_id_repay,
            "repaytype": repaytype,
            "repay_other": input_id_repayother,
            "repay_remainprice" : repay_remainprice,
            "refunddate": refunddate
        }
    };
    CallHandler("adm_get", senddata, function (res) {
        var code = parseInt(res.code);
        if (code == 100) {
            C_showToast("성공", "성공적으로 환불되었습니다.", function () {});
        } else {
            C_showToast("실패", "환불되지 않았습니다.관리자에게 문의해 주세요.", function () {});
        }
        hideModalDialog();
        hideModalDialog();
        hideModalDialog();
        hideModalDialog();
        header_search(uid);
    }, function (err) {
        C_showToast("에러", "" + err, function () {});
        hideModalDialog();
    });
}

//날짜가 없는 단순 기타상품은 숨김기능을 사용할 수 있다.
function nShowHideOther(uid,othercoupon){
     var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");
    
      
    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "hideother",
        value: {
            "useruid": uid,
            "othercoupon": othercoupon,
           
        }
    };
    CallHandler("adm_get", senddata, function (res) {
        var code = parseInt(res.code);
        if (code == 100) {
            C_showToast("성공", "해당상품을 숨김처리하였습니다.", function () {});
        } 
        hideModalDialog();
        hideModalDialog();
        hideModalDialog();
        header_search(uid);
    }, function (err) {
        C_showToast("에러", "" + err, function () {});
        hideModalDialog();
    });
}
