function sendBaseCouponPayment(pm_idx, callback) {

    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");

    var payment = getPaymentInList(pm_idx);
    var value = {
        "useruid": click_coupondata.useruid,
        "userid": click_coupondata.userid,
        "username": click_coupondata.username,
        "coupon": click_coupondata.coupon,
        "payment": payment
    };
    
    if(!value.coupon.paymenttype)value.coupon.paymenttype = "0";
	if(!value.payment.pm_paymenttype)value.payment.pm_paymenttype = "0";

    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "newbasecouponupdate",
        value: value
    };

    CallHandler("adm_get", senddata, function (res) {
        callback(res);
    }, function (err) {
        alertMsg(err);
    });

}

function getBaseCoupon(mbsidx) {
    var basecoupon = null;
    for (var i = 0; i < simple_mbs_coupons.length; i++) {
        if (parseInt(simple_mbs_coupons[i].mbs_idx) == parseInt(mbsidx)) {
            basecoupon = simple_mbs_coupons[i];
            break;
        }
    }
    return basecoupon;
}
