function getClickCouponPaymentData(type, pm_date) {
    if (type == "coupon") {
        return click_coupondata.coupon;
    } else if (type == "payment") {
        var paymentdata = null;
        for (var i = 0; i < click_coupondata.payments.length; i++) {
            if (click_coupondata.payments[i].pm_date == pm_date) {
                paymentdata = click_coupondata.payments[i];
                break;
            }
        }
        return paymentdata;
    }
}

function updateClickCouponPaymentData(coupon, paymentdata) {
    click_coupondata.coupon = coupon;

    if (paymentdata && click_coupondata.payments)
        for (var i = 0; i < click_coupondata.payments.length; i++) {
            if (click_coupondata.payments[i].pm_date == paymentdata.pm_date) {
                click_coupondata.payments[i] = paymentdata;
                break;
            }
        }
}


function changeDetailButtoncolor(id) {
    var nowflg = false;
    if (before_detail_btndata_id == id) {
        isdeteil_btn_flg = isdeteil_btn_flg ? false : true;
        nowflg = isdeteil_btn_flg;
    } else {
        nowflg = true;

        //이전 버튼 색깔
        var before_btn = document.getElementById(before_detail_btndata_id);
        if (before_btn) {
            if (before_btn.innerHTML == "삭제") {
                before_btn.style.backgroundColor = "#f1416c";
                before_btn.style.color = "white";
            } else {
                before_btn.style.backgroundColor = "#e4e6ef";
                before_btn.style.color = "#3f4254";
            }

        }
    }


    //현재 선택한 버튼 색깔
    var btn = document.getElementById(id);
    if (nowflg) {
        btn.style.backgroundColor = "#5591fe";
        btn.style.color = "white";
    } else {

        if (btn.innerHTML == "삭제") {
            btn.style.backgroundColor = "#f1416c";
            btn.style.color = "white";
        } else {
            btn.style.backgroundColor = "#e4e6ef";
            btn.style.color = "#3f4254";
        }
    }

    //입력박스를 활성화할건지
    if (id == "detail_button_change") showInputDetailTags(nowflg);
    else showInputDetailTags(false);


    before_detail_btndata_id = id;

}

