function pushDirectMessage(key, len) {

    var title = "";
    var message = "";
    var centername = getData("nowcentername");
    if (key == "data_locker_over_member") {
        title = centername + " 라커 기간종료 안내";
        message = "#{이름}님 #{라커번호}번 라커 기간이 종료되었습니다. 물건을 가져가세요. 종료일 기준 14일 후에 라커물건은 폐기처분합니다.";
    } else if (key == "data_locker_limit_member") {
        title = centername + " 라커 기간임박 안내";
        message = "#{이름}님 #{라커번호}번 라커 기간이 곧 종료될 예정입니다. 14일안에 물건을 가져가시거나 라커기간을 연장하세요.";
    }

    var message_tag =
        "<div style='width:100%;height:90px; background-color:#ffffff; border:1px solid #e4e6ef; border-radius:10px;'>" +
        "<div style='width:100%;height:45px;background-color:#f5f8fa; border-radius:10px 10px 0 0; border-bottom:1px solid #e4e6ef;'>" +
        "<label style='float:left;font-size: 16px; color:#3f4254;font-weight:500; text-align:left;margin-top:10px;margin-left:30px'>제목 </label>" +
        "</div>" +
        "<div style='width:100%;height:45px;border-radius:0 0 10px 10px;text-align:left' >" +
        "<input id='input_direct_push_title' value='" + title + "' style='width:100%;margin-top:10px;margin-left:10px;margin-right:10px;background:none;border:0px;outline:none'/>" +
        "</div>" +
        "</div><br>" +
        "<div style='width:100%;height:auto; background-color:#ffffff; border:1px solid #e4e6ef; border-radius:10px;'>" +
        "<div style='width:100%;height:45px;background-color:#f5f8fa; border-radius:10px 10px 0 0; border-bottom:1px solid #e4e6ef;'>" +
        "<label style='float:left;font-size: 16px; color:#3f4254;font-weight:500; text-align:left;margin-top:10px;margin-left:30px'>내용 </label>" +
        "</div>" +
        "<div style='width:100%;' >" +
        "<textarea class='form-control'  style='height:100px;border-radius:0 0 10px 10px;' id='input_direct_push_message' value='" + message + "'>" + message + "</textarea>" +
        "</div>" +
        "</div>";




    //            "<br><text class='textevent' style='float:left'>제목</text><br><input class='form-control' id='input_direct_push_title' value='"+title+"'/><br><text  style='float:left' class='textevent'>내용</text><br><textarea class='form-control'  style='height:100px' id='input_direct_push_message' value='"+message+"'>"+message+"</textarea><br>";


    var style = {
        bodycolor: "#ffffff",
        size: {
            width: "30%",
            height: "100%"
        }
    };

    showModalDialog(document.body, "총 " + len + "명에게 메세지(SMS/앱푸시)를 보내시겠습니까 ?", message_tag, "보내기", "취소", function () {

        var input_direct_push_title = document.getElementById("input_direct_push_title").value;
        var input_direct_push_message = document.getElementById("input_direct_push_message").value;

        getCustomUsers(key, input_direct_push_title, input_direct_push_message, null, null, function (res) {
            var code = parseInt(res.code);
            if (code == 100) {

                var smsuser_len = res.sms_users.length;
                var pushuser_len = res.push_users.length;
                if (sendPointCheck(smsuser_len, pushuser_len, message)) {
                    sendAppPushMessage(getToday(), res.push_users);
                    sendSMSMessage(getToday(), res.sms_users);
                }

            }
        });

    }, function () {
        hideModalDialog();
    }, style);


}

