function locker_click(lockertype, id, update_data) {

    loc_selected_locker_id = id;
    var simple_id_locker_number = document.getElementById("simple_id_locker_number");
    var simple_id_locker_pass = document.getElementById("simple_id_locker_pass");
    var obj = search_locker(id);

    if (!update_data && C_DateOverCheck(obj.starttime, obj.endtime) != 0) {
        getUserData(obj.useid, function (res) {
            var username = "";
            var phone_tag = "";
            var user = null;
            if (res.code == "100") {
                user = res.message.length > 0 ? res.message[0] : null;
                username = user ? user.mem_username : "미지정";
                phone_tag = user && user.mem_phone ? "<b>• 전화번호&nbsp;:&nbsp;</b>" + user.mem_phone + "" : "";
            }
            // •ㅋ (middot, bull) - 엘비
            //가운데점 ,가운데 , 중앙  •   dot 
            var locker_desc = obj.desc ? obj.desc : "";
            var message = "<div class='fmont' style='width:100%;height:auto;text-align:left;padding-left:6px;font-size:14px'><button class='btn btn-primary' type='button' onclick='searchuser(\"" + obj.useid + "\")'>" + username + "[" + obj.useid + "]</button>&nbsp; 님이 사용중인 라커입니다.<br><br><div style='width:100%;height:auto;padding:10px 10px 10px 20px;background-color:#f1faff;border:1px solid #3cb5f9;border-radius:7px;border-top-style: dashed;border-right-style: dashed;border-bottom-style: dashed;border-left-style: dashed;'>" + phone_tag + "<br><b>• 라커비밀번호 : </b>" + obj.pass + "<br><b>• 기간&nbsp;:&nbsp;</b>" + obj.starttime.substr(0, 10) + " ~ " + obj.endtime.substr(0, 10) + "<br><b>• 설명 : </b>" + locker_desc + "</div></div>";
            //alertMsg(message);

            var btn_txt = "고객정보보기";
            //if(isPermission(201) && lockertype){
            if (isPermission(201)) {
                if (user.mem_fcmtoken && user.mem_fcmtoken == "")
                    btn_txt = "문자메세지 보내기";
                else
                    btn_txt = "앱푸시 보내기";
            }
            showModalDialog(document.body, "(" + id + "번)&nbsp;사용중인 라커", message, "확인", btn_txt, function () {
                hideModalDialog();
            }, function (err) {

                //if(isPermission(201) && lockertype){
                if (isPermission(201)) {
                    if (user)
                        sendLockerUserPushSMS(lockertype, id, user);
                    else
                        alertMsg("고객정보를 찾을 수 없습니다.");

//                    sendLockerUserPushSMS(lockertype, id, user);

                } else {

                    searchuser(obj.useid);
                }

            });
        });

        //        var message = "이미 사용중인 라커입니다.<br>고객번호 : "+obj.useid+" ,  라커비밀번호 : "+obj.pass+"<br>기간:"+obj.starttime.substr(0,10)+" ~ "+obj.endtime.substr(0,10);
        //        showModalDialog(document.body, "("+id+"번)&nbsp;사용중인 라커", message, "고객정보보기", "확인", function () {
        //                hideModalDialog();
        //                hideModalDialog();
        //                header_search(obj.useid);
        //            }, function (err) {
        //                clog("err ",err);
        //                hideModalDialog();
        //                hideModalDialog();
        //            });



        return;
    } else {
        if (simple_id_locker_number) { // 고객회원가입하기 화면일때 , 갱신하기일때
            simple_id_locker_number.innerHTML = obj.name;
            simple_id_locker_pass.value = obj.pass;
            hideModalDialog();
        } else { //어드민 화면일때

            var locker_div = document.createElement("div");
            var style = {

                size: {
                    width: "80%",
                    height: "100%"
                }
            };
            var header = "※ " + id + " 번 라커 설정하기";

            locker_div.innerHTML =
                "<div id='div_locker_search_user' align='center' style='width:100%; height:120px; background-color:#f5f8fa;padding-top:35px'>" +
                "<div style='width:670px;height:40px;background-color:#ffffff;border-radius:10px;box-shadow: 0px 5px 10px 0px rgba(16, 26, 35, 0.1);'>" +
                "<span><img onclick='user_search()' src='./img/icon_search.png' style='width:16px;height:14px;margin:13px 7px 15px 7px '></span>" +
                "<span>" +
                "<input id='id_user_search' onkeyup='locker_search_enter()' type='text' placeholder='이름,폰,회원번호로 찾기' aria-label='Search' aria-describedby='basic-addon2' title='이름, 회원번호 , 전화번호 끝 4자리 , 전체전화번호 로 찾을 수 있습니다. ' style='width:560px; height:40px;border: none; background: transparent;outline: none;webkit-text-fill-color: #000;-webkit-box-shadow: 0 0 0px 1000px #fff inset;box-shadow: 0 0 0px 1000px #fff inset;transition: background-color 5000s ease-in-out 0s;'/>" +
                "</span>" +
                "<button onclick='user_search()'  class='btn' style='border:0px;margin-top:-5px;margin-left:5px;cursor:pointer;width:60px; height:34px;border-radius:8px;background-color:#0c0c0d;color:white;outline:none'>검색</button>" +
                "</div>" +
                "</div>" +
                "<div id='search_body'></div>";



            //이미 찾는 유저가 있다면 바로 서치한다.
            if (locker_type_userid) user_search(locker_type_userid, update_data);


            showModalDialog(document.body, header, locker_div.innerHTML, "취소", "라커설정하기", function () {
                hideModalDialog();
            }, function () {
                if (!document.getElementById("selected_locker_user")) {
                    alertMsg("회원을 선택해 주세요");
                    return;
                }
                //                clog("aa ",document.getElementById("locker_payment_type").value);
                if (!document.getElementById("locker_payment_type").value) {
                    alertMsg("결제방법을 선택해 주세요");
                    return;
                }
                
                if (!document.getElementById("lockerstart").value) {
                    alertMsg("시작일을 선택해 주세요");
                    return;
                }
                
                if (!document.getElementById("lockerend").value) {
                    alertMsg("종료일을 선택해 주세요");
                    return;
                }
                
                var lockerpaymentdate = document.getElementById("lockerpaymentdate").value;
                var lockerstart = document.getElementById("lockerstart").value;
                var lockerend = document.getElementById("lockerend").value;
                
                if(compare_date(lockerstart, lockerend) > 0){
                    alertMsg("시작일은 종료일보다 이전날짜여야 합니다.");
                    return;
                }
                
                var lockerpass = document.getElementById("lockerpass").value;
                var lockerprice = document.getElementById("lockerprice").value;

                var desc = document.getElementById("lockerdesc");
                var paymenttype = document.getElementById("locker_payment_type").value;
                var payment_other = document.getElementById("locker_payment_other").value;

                var locker_card = parseInt(paymenttype) == 1 ? lockerprice : 0;
                var locker_cash = parseInt(paymenttype) == 2 ? lockerprice : 0;

                desc.value = desc.value + " " + TXT_WON + lockerprice;
                var data = {
                    lockerpaymentdate: lockerpaymentdate,
                    useid: loc_userdata.mem_userid,
                    lockerid: loc_selected_locker_id,
                    starttime: lockerstart,
                    endtime: lockerend,
                    lockerpass: lockerpass,
                    price: parseCommaInt(lockerprice),
                    card: parseCommaInt(locker_card),
                    cash: parseCommaInt(locker_cash),
                    desc: desc.value,
                    paymenttype: paymenttype,
                    paymentother: payment_other
                }

                var senddata = {
                    type: "setlockeruser",
                    centercode: getData("nowcentercode"),
                    value: data
                }

                CallHandler("adm_get", senddata, function (res) {
                    clog("res ", res);
                    //                    clog("res ",res);
                    //                    clog("res ",res);
                    hideModalDialog();
                    hideModalDialog();
                    hideModalDialog();
                    if (res.code == 100) {
                        C_showToast("라커설정완료!", id + "번 라커를 " + loc_userdata.mem_username + "님께 설정하였습니다.", function () {});
                    } else
                        C_showToast("라커설정불가!", "" + res.message, function () {});

                    header_search(loc_userdata.mem_userid);
                }, function (err) {
                    clog("err ", err);
                    hideModalDialog();

                });


            }, style);


        }
    }

}

