function price_click() {
    var locker_payment_type = document.getElementById("locker_payment_type");
    locker_payment_type.value = "";
    before_selectlocker_paymenttype = 0;
}
var before_selectlocker_paymenttype = 0;

function select_locker_paymenttype() {
    var locker_payment_type = document.getElementById("locker_payment_type");
    var lockerprice = document.getElementById("lockerprice");
    var nowtype = parseInt(locker_payment_type.value); //1 카드 , 2 : 현금
    var price = parseCommaInt(lockerprice.value);

    if (locker_payment_type.value) {

        if (before_selectlocker_paymenttype != 1 && nowtype == 1) { //카드
            //            price = price*1.1;//neel_vat
            price = addVAT(null, price);
        } else if (before_selectlocker_paymenttype == 1 && nowtype == 2) { //현금
            //            price = price/11*10;  //neel_vat
            price = subVAT(null, price);
        }
        lockerprice.value = CommaString(price);
        before_selectlocker_paymenttype = nowtype;
    }


}

function number_format(_number) {
    if (!_number) _number = 0;
    var number = _number + "";
    number = number.replace(/\,/g, "");
    var nArr = String(number).split('').join(',').split('');
    for (var i = nArr.length - 1, j = 1; i >= 0; i--, j++)
        if (j % 6 != 0 && j % 2 == 0) nArr[i] = '';
    var str = nArr.join('');
    //    str = str.replaceAll("-,","-");
    str = str.replace(/-,/g, '-');
    return str;
}

function number_format_to_number(_number) {
    var number = _number + "";
    var number = number.replace(/,/g, '');
    return number;
}

