function lockerdate_onchange(update_data) {

    var lockerstart = document.getElementById("lockerstart");
    var lockerend = document.getElementById("lockerend");
    var lockerprice = document.getElementById("lockerprice");
    var lockerpass = document.getElementById("lockerpass");
    var locker_total_day = document.getElementById("locker_total_day");
    var lockerdesc = document.getElementById("lockerdesc");
    //     var desc = "라커 사용기간 : "new_starttime+" ~ "+new_endtime+" (총 "+day+"일)";


    var hhmmss = " 00:00:00";
    var lday = getDay(lockerstart.value, lockerend.value);
    if (update_data) {

        //시작일을 변경했거나 종료일을 변경했다면 결제방법을 초기화한다.
        if (update_data == 1 || update_data == 2) {
            var locker_payment_type = document.getElementById("locker_payment_type");
            locker_payment_type.value = "";
            before_selectlocker_paymenttype = 0;
        } else {
            lockerstart.value = locker_type_user_starttime;
            lockerend.value = locker_type_user_endtime;
            lockerpass.value = update_data.pass;
            lday = update_data.day;
        }

    }
    if (isNaN(lday)) lday = 0;
    locker_total_day.innerHTML = "<span style='color:#f1416c'>(" + lday + "일)</span>";


    var month = parseInt(lday / 30);
    var day = parseInt(lday % 30);
    var monthprice = parseInt(loc_alllocker[0].monthprice);
    var dayprice = parseInt(loc_alllocker[0].dayprice);



    var total = monthprice * month + dayprice * day;
    if (isNaN(total)) total = 0;

    lockerprice.value = total;
    lockerdesc.value = "라커 사용기간 : " + locker_type_user_starttime + " ~ " + locker_type_user_endtime + " (총 " + lday + "일)";
    //    clog("*** lockerdesc.value ",lockerdesc.value);

}

function search_locker(id) {
    var locker = loc_alllocker;
    var rdata = null;
    for (var i = 0; i < locker.length; i++) {
        for (var j = 0; j < locker[i].data.length; j++) {
            for (var k = 0; k < locker[i].data[j].length; k++) {
                //                        clog("id "+id+"  locker[i].data[j][k].name "+locker[i].data[j][k].name);
                if (id == locker[i].data[j][k].name) {
                    rdata = locker[i].data[j][k];
                    //                    clog("locker[i].data[j] ",locker[i].data[j][k]);
                    break;
                }
            }
        }
    }
    return rdata;
}

function resetlockerdata(id) {
    var locker = loc_alllocker;
    for (var i = 0; i < locker.length; i++) {
        for (var j = 0; j < locker[i].data.length; j++) {
            for (var k = 0; k < locker[i].data[j].length; k++) {
                //                        clog("id "+id+"  locker[i].data[j][k].name "+locker[i].data[j][k].name);
                if (id.trim() == locker[i].data[j][k].name.trim()) {
                    locker[i].data[j][k].useid = "";
                    locker[i].data[j][k].starttime = "";
                    locker[i].data[j][k].endtime = "";
                    locker[i].data[j][k].pass = "";

                    break;
                }
            }
        }
    }
}

