//json object array 특정 변수로 정렬하기
//ex )  arr.sort(sort_by('mbs_type', false, (a) =>  a.toUpperCase())); 
//      arr.sort(sort_by('mbs_use_centercode', true, parseInt));
function sort_by(field, reverse, primer) {

    const key = primer ?
        function (x) {
            if (!x) return null;
            return primer(x[field])
        } :
        function (x) {
            if (!x) return null;
            return x[field]
        };

    reverse = !reverse ? 1 : -1;

    return function (a, b) {
        return a = key(a), b = key(b), reverse * ((a > b) - (b > a));
    }
}
function new_sort(arr,key,isupper){
    //오름차순
    if(isupper){
        return arr.sort(function (a, b) {
            const valueOfKeyA = a[key].toUpperCase();
            const valueOfKeyB = b[key].toUpperCase();
            return valueOfKeyA.localeCompare(valueOfKeyB, undefined, {
              numeric: true,
              sensitivity: 'base',
            });
          });
    }
    //내림차순
    else{
        return arr.sort(function (a, b) {
            const valueOfKeyA = a[key].toUpperCase();
            const valueOfKeyB = b[key].toUpperCase();
            return valueOfKeyB.localeCompare(valueOfKeyA, undefined, {
              numeric: true,
              sensitivity: 'base',
            });
          });
    }
}

function StringEnterToBR(pushdata) {
    var title = pushdata.title ? pushdata.title : null;
    var message = pushdata.message ? pushdata.message : null;
    var titles = pushdata.titles ? pushdata.titles : null;
    var messages = pushdata.messages ? pushdata.messages : null;

    if (title && message) {
        title = replaceEnterToBR(title);
        message = replaceEnterToBR(message);
        pushdata.title = title;
        pushdata.message = message;
    } else {
        for (var i = 0; i < titles.length; i++) {
            titles[i] = replaceEnterToBR(titles[i]);
            messages[i] = replaceEnterToBR(messages[i]);
        }
        pushdata.titles = titles;
        pushdata.messages = messages;
    }
    return pushdata;
}
function replaceEnterToPLine(msg) {
    if (msg && msg.length > 0) {
        // 모든 줄바꿈을 \n 문자열로 통일
        msg = msg.replace(/(?:\r\n|\r|\n)/g, '|');
        msg = msg.replaceAll('"', '&quot;');
    }
    return msg;
}
function replacePLineToEnter(msg) {
    if (msg && msg.length > 0) {
        // | 를 실제 줄바꿈(\n)으로 변환
        msg = msg.replace(/\|/g, '\n');

        // HTML 엔티티로 바꿨던 쌍따옴표도 원복
        msg = msg.replaceAll('&quot;', '"');
    }
    return msg;
}
function replaceEnterToNewline(msg) {
    if (msg && msg.length > 0) {
        // 모든 줄바꿈을 \n 문자열로 통일
        msg = msg.replace(/(?:\r\n|\r|\n)/g, '\\n');
        msg = msg.replaceAll('"', '&quot;');
    }
    return msg;
}
function replaceEnterToBR(msg) {
    if (msg && msg.length > 0) {
        msg = msg.replaceAll(/(?:\r\n|\r|\n)/g, '<br>');
        msg = msg.replaceAll("\"", "&quot;");
    }
    return msg;
}

function replaceBRToEnter(msg) {
    if (msg && msg.length > 0) {
        msg = msg.replaceAll("<br>", "\r\n");
    }
    return msg;
}


