//2차원배열에서 특정변수를 중복값 제거한 후 리턴
function trim_sort_2array(objs, key) {
    var arr = [];
    for (var i = 0; i < objs.length; i++) {
        var issame = false;
        for (var j = 0; j < arr.length; j++) {
            if (arr[j][key] == objs[i][key]) {
                issame = true;
            }
        }
        if (!issame)
            arr.push(objs[i]);
    }
    //    var set = new Set(objs);
    //    return Array.from(set);
    //    

    return arr;
}

function trim_sort_1array(objs) {
    var arr = [];
    for (var i = 0; i < objs.length; i++) {
        var issame = false;
        for (var j = 0; j < arr.length; j++) {
            if (arr[j] == objs[i]) {
                issame = true;
            }
        }
        if (!issame)
            arr.push(objs[i]);
    }
    //    var set = new Set(objs);
    //    return Array.from(set);
    //    

    return arr;
}
//subkey ex) date 날짜가 최신으로 간추리기
function trim_sort_2array_subkey(objs, key, subkey) {
    var arr = [];
    for (var i = 0; i < objs.length; i++) {
        var issame = false;
        for (var j = 0; j < arr.length; j++) {
            if (arr[j][key] == objs[i][key]) { //arr

                issame = true;
                if (subkey && issame && compare_date(arr[j][subkey], objs[i][subkey]) == -1) {
                    arr[j] = objs[i];
                }
            }

        }
        if (!issame)
            arr.push(objs[i]);
    }
    //    var set = new Set(objs);
    //    return Array.from(set);
    //    

    arr.sort(sort_by('date', false, (a) => a.toUpperCase()));


    return arr;
}
