function click_default_btn(isopt) {
    var opt = isopt && isopt == 1 ? "opt_" : "";
    var default_set_btn = document.getElementById(opt + "default_set_btn");
    var set_locker_btn = document.getElementById(opt + "set_locker_btn");
    var set_reservationtime_btn = document.getElementById(opt + "set_reservationtime_btn");
    var set_alldelaytime_btn = document.getElementById(opt + "set_alldelaytime_btn");

    if (default_set_btn.checked) {
        set_locker_btn.checked = true;
        set_reservationtime_btn.checked = true;
        set_alldelaytime_btn.checked = true;


    } else {
        set_locker_btn.checked = false;
        set_reservationtime_btn.checked = false;
        set_alldelaytime_btn.checked = false;

    }
}

function click_in_default_btn(isopt) {
    var opt = isopt && isopt == 1 ? "opt_" : "";
    var default_set_btn = document.getElementById(opt + "default_set_btn");
    var set_locker_btn = document.getElementById(opt + "set_locker_btn");
    var set_reservationtime_btn = document.getElementById(opt + "set_reservationtime_btn");
    var set_alldelaytime_btn = document.getElementById(opt + "set_alldelaytime_btn");

    if (default_set_btn.checked) {
        if (!set_locker_btn.checked && !set_reservationtime_btn.checked && !set_alldelaytime_btn.checked)
            default_set_btn.checked = false;

    } else {
        if (set_locker_btn.checked || set_reservationtime_btn.checked || set_alldelaytime_btn.checked)
            default_set_btn.checked = true;
    }
}

function checked(list, num) {
    var checked = "";
    if (list)
        for (var i = 0; i < list.length; i++) {
            if (num == parseInt(list[i])) {
                checked = "checked";
                break;
            }
        }
    return checked;
}
//문자열에서 숫자만 추출한다.
function getStringInNumber(str) {
    var regex = /[^0-9]/g; // 숫자가 아닌 문자열을 선택하는 정규식
    var result = str.replace(regex, ""); // 원래 문자열에서 숫자가 아닌 모든 문자열을 빈 문자로 변경
    //clog(result);	 
    var rvalue = result == "" ? 0 : parseInt(result);
    return rvalue;
}

function getPaymentData(value, callback) {


    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");

    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "getpaymentdata",
        value: value
    };
    //        clog("year is ",v);
    CallHandler("adm_get", senddata, function (res) {
        callback(res);
    }, function (err) {
        alertMsg(err);
    });
}
