function onchangeRemainData(isinputchange, inputid, paymentid, _remaindata) {
    clog("onchangeRemainData ");
    var remaindata = JSON.parse(_remaindata);

    var input_cashtotal = document.getElementById("input_cashtotal_" + paymentid); // 현금기준 미수금총액
    var inputcard = document.getElementById("input_cardremain_" + paymentid); //카드 입력금액 
    var inputcash = document.getElementById("input_cashremain_" + paymentid); // 현금 입력금액
    var inputrdiscount = document.getElementById("input_discount_" + paymentid); //할인금액
    var inputtotal = document.getElementById("input_total_" + paymentid); //총결제금액
    var inputrremain = document.getElementById("input_remain_" + paymentid); //다시 남은 금액
    var id_remain_payment = document.getElementById("remain_payment_" + paymentid); //결제방법 
    var all_cash_total = parseCommaInt(input_cashtotal.value);
    //        var remainprice = cashtotal-parseCommaInt(inputcard.value);
    //        remainprice += parseInt(remaindata.remain_cash)-parseCommaInt(inputcash.value);

    var ctotal = all_cash_total;
    var cash = parseCommaInt(inputcash.value);
    var card = parseCommaInt(inputcard.value);
    var discount = parseCommaInt(inputrdiscount.value);
    var remain = parseCommaInt(inputrremain.value);
    var total = parseCommaInt(inputtotal.value);


    //        //카드
    //        if(isinputchange == 1){
    //            remain =  ctotal- (cash + subVAT(null,card))-discount;
    //        }
    //        //현금
    //        else if(isinputchange == 2){
    //            card = addVAT(null,(ctotal - (cash + remain)));
    //        }
    //        //미수금
    //        else if(isinputchange == 3){
    //        }
    //        //할인
    //        else if(isinputchange == 4){  
    //        }
    //    

    //카드입력 아닐때
    if (isinputchange != 1) {

        //            card = (ctotal - (cash + remain))*1.1; //카드입력일때 빼고 카드 자동계산 //neel_vat
        card = addVAT(null, (ctotal - (cash + remain + discount)));
    } else if (isinputchange != 2 && isinputchange != 3 && isinputchange != 4) {
        //            remain = ctotal- (cash + (card/11*10));     //현금입력일때, 미수금 빼고 미수금 자동계산//neel_vat
        remain = ctotal - (cash + subVAT(null, card) + discount);
    }

    if (isinputchange == 3) {
        remain = parseCommaInt(inputrremain.value);
        card = addVAT(null, ctotal - (cash + remain + discount));

    }
    if (isinputchange == 4) {
        card = addVAT(null, ctotal - (cash + remain + discount));
        clog("************ isinputchange " + card);
    }

    if (card < 0) {
        cash = cash + card;
        card = 0;
    }

    inputcard.value = number_format(Math.floor(card));
    inputcash.value = number_format(Math.floor(cash))

    inputrdiscount.value = number_format(Math.floor(discount));
    inputrremain.value = number_format(Math.floor(remain));
    inputtotal.value = number_format(Math.floor(card + cash));
    //        inputChangeComma(inputid);
    if (card == 0 && cash == 0) id_remain_payment.selectedIndex = 0;
    else if (card > 0 && cash == 0) id_remain_payment.selectedIndex = 1;
    else if (card == 0 && cash > 0) id_remain_payment.selectedIndex = 2;
    else id_remain_payment.selectedIndex = 3;
}
var defaultremaindata = null;

function btn_remain(pmidx,paymentid, useruid, userid, username, couponid, remainid, _remaindata) {

    //paymentid 현재결제내역 pm_date,   remainid : 원조 미수금 pm_date
    checkRemainPrice(pmidx,useruid, couponid, paymentid, remainid, function (result) {
        
        var code = parseInt(result.code);
        if (code == 100) {
            var coupon = result.message;
            var locker = result.locker;
            var other = result.other;
           
            if(coupon.isdelete && coupon.isdelete == "D"){
                var alertmsg = "이미 삭제된 회원권입니다.";
                if(parseInt(coupon.repay) != 0)
                    alertmsg = "이미 환불된 회원권입니다.";
                alertMsg(alertmsg);
                return;
            }
            
            if(coupon){
                 // 남은금액이 있다.
                var groupid = coupon && coupon.groupid ? coupon.groupid : "";
                var value = {
                    couponid: couponid,
                    useruid: useruid,
                    groupid: groupid

                }
                getPaymentData(value, function (res) {
                    var payment_datas = code == 100 ? res.message : null;
                    click_coupondata = {
                        "useruid": useruid,
                        "userid": userid,
                        "username": username,
                        "coupon": coupon,
                        "payments": payment_datas
                    };
                    nShowGetRemainPrice(paymentid,true);
                });
            }else {
                if(locker){
                    click_coupondata = {
                        "useruid": useruid,
                        "userid": userid,
                        "username": username,
                        "coupon": null,
                        "payments": locker.payment
                    };   
                }else if(other){
                    click_coupondata = {
                        "useruid": useruid,
                        "userid": userid,
                        "username": username,
                        "coupon": null,
                        "payments": other.payment
                    };
                }
                 
                nShowGetRemainPrice(paymentid,true,false,locker,other);
            }
            
        } else {
            alertMsg(result.message);
        }
        
    });

}

function change_remain_paymenttype(paymentid, _remaindata) {
    //        var remaindata = defaultremaindata;
    clog("_remaindata ", _remaindata);
    var remaindata = JSON.parse(_remaindata); //
    clog("remaindata ", remaindata);
    var inputcard = document.getElementById("input_cardremain_" + paymentid); //카드
    var inputcash = document.getElementById("input_cashremain_" + paymentid); //현금
    var inputtotal = document.getElementById("input_total_" + paymentid); // 결제금액
    var inputrremain = document.getElementById("input_remain_" + paymentid); //잔여금액

    var remain_payment = document.getElementById("remain_payment_" + paymentid).value;

    var cardprice = 0;
    var cashprice = 0;
    var totalprice = 0;
    var remainprice = 0;
    switch (remain_payment) {
        case "1": //카드1
            //                cardprice = Math.floor(parseCommaInt(remaindata.remain)*1.1);       //neel_vat         
            cardprice = Math.floor(addVAT(null, parseCommaInt(remaindata.remain)));
            totalprice = cardprice;

            inputcard.value = totalprice;
            inputcash.value = "0";



            remainprice = 0;


            break;
        case "2": //현금

            cashprice = Math.floor(parseCommaInt(remaindata.remain));
            totalprice = cashprice;

            inputcard.value = "0";
            inputcash.value = totalprice;


            remainprice = 0;

            break;

            //            case "3": //환불
            //                break;

        case "4": //카드+현금
            cardprice = Math.floor(parseCommaInt(inputcard.value));
            cashprice = Math.floor(parseCommaInt(inputcash.value));
            //                var mcardprice =  Math.floor(parseCommaInt(inputcard.value)/11*10);//neel_vat
            var mcardprice = Math.floor(subVAT(null, parseCommaInt(inputcard.value)));
            totalprice = cardprice + cashprice;

            remainprice = parseInt(remaindata.remain) - (mcardprice + cashprice);
            break;
    }
    //        clog("remaindata.remain"+remaindata.remain+" totalprice"+totalprice);
    //        remainprice = Math.floor(parseInt(remaindata.remain) - totalprice);
    //        if(remainprice < 0)remainprice = 0;
    inputcard.value = number_format(cardprice);
    inputcash.value = number_format(cashprice);
    inputtotal.value = number_format(Math.floor(totalprice));
    inputrremain.value = remainprice;


}


