function onChanageGXUpdateCoupon(type) {



    var gxid_coupon_select = document.getElementById("gxid_coupon_select"); //type 1
    var gxid_starttime = document.getElementById("gxid_starttime"); //type 3
    var gxid_endtime = document.getElementById("gxid_endtime"); //type 4
    var gxid_addcount = document.getElementById("gxid_addcount"); //type 777
    var gxid_addprice = document.getElementById("gxid_addprice"); //type 5   
    var gxid_paymenttype = document.getElementById("gxid_paymenttype"); //type 7

    var gxid_card = document.getElementById("gxid_card"); //type 30
    var gxid_cash = document.getElementById("gxid_cash"); //type 31
    var gxid_remain = document.getElementById("gxid_remain"); //type 32
    var gxid_discount = document.getElementById("gxid_discount"); //type 33
    //    var gxid_totalprice = document.getElementById("gxid_totalprice");         
    var gxid_totalremain = document.getElementById("gxid_totalremain");

    var gxid_note = document.getElementById("gxid_note");

    var card = parseCommaInt(gxid_card.value);
    var cash = parseCommaInt(gxid_cash.value);
    var remain = parseCommaInt(gxid_remain.value);
    var totalprice = parseCommaInt(gxid_addprice.value);
    var totalremain = parseCommaInt(gxid_totalremain.value);

    var paymenttype = parseInt(gxid_paymenttype.value);
    //결제타입 변경
    if (type == 7) {
        if (paymenttype == 1) { //card
            card = totalprice;
            cash = 0;
            remain = 0;
            totalprice = card + cash + remain;
            totalremain = card + cash;

        } else if (paymenttype == 2) { //cash
            card = 0;
            cash = totalprice;
            remain = 0;
            totalprice = card + cash + remain;
            totalremain = card + cash;
        } else if (paymenttype == 3) { //repay

        } else if (paymenttype == 4) { // card + cash

        }
    }
    //카드 ,현금 , 미수금 , 할인x
    if (type == 30 || type == 31 || type == 32 || type == 33) {
        if (type == 30 || type == 31) {
            remain = totalprice - (card + cash);
        } else if (type == 32) {
            card = totalprice - (remain + cash);
        }

    }

    if (card == 0 && cash == 0) {
        paymenttype = 0;
    } else if (card > 0 && cash == 0) {
        paymenttype = 1;
    } else if (card == 0 && cash > 0) {
        paymenttype = 2;
    } else if (card > 0 && cash > 0) {
        paymenttype = 4;
    } else if (card < 0 || cash < 0) {
        paymenttype = 3;
    }
    totalprice = card + cash + remain;
    totalremain = card + cash;

    gxid_paymenttype.value = paymenttype + "";
    gxid_card.value = CommaString(card);
    gxid_cash.value = CommaString(cash);
    gxid_remain.value = CommaString(remain);
    //    gxid_totalprice.value = CommaString(totalprice);
    gxid_totalremain.value = CommaString(totalremain);


}

