var before_c_paymenttype = 0;

function onChanageUpdateCoupon(type, istermtype, key) {
    clog("onChanageUpdateCoupon type " + type);
    //type =>  1 :termtype select , 2: counttype select , 3: starttime , 4 : endtime , 5 : price , 6 : paymentype , 7 : note , 
    var termtype_coupon = document.getElementById("c_termtype_coupon_" + key);
    var counttype_coupon = document.getElementById("c_counttype_addcount_" + key);

    var starttime = document.getElementById("c_starttime_" + key);
    var endtime = document.getElementById("c_endtime_" + key);
    var couponprice = document.getElementById("c_couponprice_" + key);
    var lockermonth = document.getElementById("c_lockermonth_" + key);
    var lockerservicemonth = document.getElementById("c_lockerservicemonth_" + key);
    var lockerprice = document.getElementById("c_lockerprice_" + key);
    var paymenttype = document.getElementById("c_paymenttype_" + key);
    var note = document.getElementById("c_note_" + key);
    var holdingday = document.getElementById("c_holdingday_" + key);
    var gxcount = document.getElementById("c_gxcount_" + key);

    var card = document.getElementById("c_card_" + key);
    var cash = document.getElementById("c_cash_" + key);
    var remain = document.getElementById("c_remain_" + key);
    var discount = document.getElementById("c_discount_" + key);
    var totalprice = document.getElementById("c_totalprice_" + key);
    var totalremain = document.getElementById("c_totalremain_" + key);

    //if(type == 5 || type == 12){ //회원권 금액  , 라커금액 수정일때
    //    if(type == 5 || type == 12){ //회원권 금액  , 라커금액 수정일때
    //        before_c_paymenttype = 0;
    //        paymenttype.value = "";
    //    }


    var selected_coupon = null;
    //    clog("00 starttime ",starttime.value);
    for (var i = 0; i < simple_mbs_coupons.length; i++) {
        //기간제 
        if (istermtype == 1 && parseInt(simple_mbs_coupons[i]["mbs_idx"]) == parseInt(termtype_coupon.value)) {
            selected_coupon = simple_mbs_coupons[i];
            break;
        }
    }

    //라커가격설정
    var lmonth = lockermonth && lockermonth.value ? parseInt(lockermonth.value) : 0;
    var slmonth = lockerservicemonth && lockerservicemonth.value ? parseInt(lockerservicemonth.value) : 0;
    var lockerpaymonth = lmonth - slmonth;
    var loc_price = lockerpaymonth * locker_month_price;
    if (lockerprice) lockerprice.value = CommaString(loc_price);
    //    if(paymenttype.value && paymenttype.value == 1) {
    ////        loc_price = loc_price*1.1;//neel_vat
    //        loc_price = addVAT(null,loc_price);
    //    
    //    }


    var coupon_price = parseCommaInt(couponprice.value);

    switch (type) {
        case 1: //기간제 선택 회원권

            if (selected_coupon) {
                endtime.value = nextMonth(starttime.value, selected_coupon.mbs_month);
                //couponprice.value = paymenttype.value && paymenttype.value == 1 ? CommaString(parseCommaInt(selected_coupon.mbs_price)*1.1) : CommaString(parseCommaInt(selected_coupon.mbs_price));      //neel_vat          
                coupon_price = paymenttype.value && parseInt(paymenttype.value) == 1 ? addVAT(null, parseCommaInt(selected_coupon.mbs_price)) : parseCommaInt(selected_coupon.mbs_price);
                couponprice.value = CommaString(coupon_price);
                holdingday.value = selected_coupon.mbs_max_holdingday;
                if (gxcount) gxcount.value = selected_coupon.mbs_max_count;
            }

            break;
        case 2: //횟수제 선택  PT / GX
            var date = parseInt(counttype_coupon.value) * 4;
            var edate = nextDay(starttime.value, date);
            endtime.value = edate;
            break;
        case 3: // 시작시간 입력
            if (istermtype == 1) {
                endtime.value = nextMonth(starttime.value, selected_coupon.mbs_month);
            }


            break;
        case 4: // 종료시간 입력
            break;
        case 5: // 회원권 금액 입력
            //이전결제타입 카드  
            var cvalue = coupon_price;
            if (parseInt(paymenttype.value) == 1) {
                coupon_price = paymenttype.value && parseInt(paymenttype.value) != 1 ? Math.floor(cvalue) : Math.floor(cvalue);
                clog("111 cvalue " + cvalue + " coupon_price " + coupon_price);
                if (lockerprice)
                    loc_price = paymenttype.value && parseInt(paymenttype.value) != 1 ? parseCommaInt(lockerprice.value) : parseCommaInt(lockerprice.value);
            }
            //이전 결제타입 카드아님
            else {
                coupon_price = paymenttype.value && parseInt(paymenttype.value) == 1 ? Math.floor(addVAT(null, cvalue)) : Math.floor(cvalue);
                clog("222 cvalue " + cvalue + " coupon_price " + coupon_price + " paymenttype.value " + paymenttype.value + " addVAT(null,cvalue) " + addVAT(null, cvalue));

                if (lockerprice)
                    loc_price = paymenttype.value && parseInt(paymenttype.value) == 1 ? addVAT(null, parseCommaInt(lockerprice.value)) : parseCommaInt(lockerprice.value);
            }
            break;
        case 6: // 총가격 입력

            break;
        case 16: // 할인금 입력

            break;
        case 7: // 결제타입 카드 , 현금 입력
        case 5: //회원권 금액 입력

            var cvalue = coupon_price;
            clog("000 cvalue " + cvalue + " coupon_price " + coupon_price);
            if (paymenttype.value == "4") {

            } else {
                //이전결제타입 카드  
                if (before_c_paymenttype == 1) {
                    coupon_price = paymenttype.value && parseInt(paymenttype.value) != 1 ? Math.floor(cvalue) : Math.floor(cvalue);
                    clog("111 cvalue " + cvalue + " coupon_price " + coupon_price);
                    if (lockerprice)
                        loc_price = paymenttype.value && parseInt(paymenttype.value) != 1 ? parseCommaInt(lockerprice.value) : parseCommaInt(lockerprice.value);
                }
                //이전 결제타입 카드아님
                else {
                    coupon_price = paymenttype.value && parseInt(paymenttype.value) == 1 ? Math.floor(addVAT(null, cvalue)) : Math.floor(cvalue);
                    clog("222 cvalue " + cvalue + " coupon_price " + coupon_price + " paymenttype.value " + paymenttype.value + " addVAT(null,cvalue) " + addVAT(null, cvalue));

                    if (lockerprice)
                        loc_price = paymenttype.value && parseInt(paymenttype.value) == 1 ? addVAT(null, parseCommaInt(lockerprice.value)) : parseCommaInt(lockerprice.value);
                }
                before_c_paymenttype = parseInt(paymenttype.value);
            }
            clog("333 cvalue " + cvalue + " coupon_price " + coupon_price);
            break;
        case 8: // 특이사항 입력
            break;
        case 11: // 라커개월수 선택

            break;
        case 12: // 라커가격 입력
            if (lockerprice) loc_price = parseCommaInt(lockerprice.value);

            break;
        case 13: // 서비스 라커 라커가격 입력

            break;

    }
    if (type == 30 || type == 31 || type == 32 || type == 33) { //카드 현금 미수금 할인금 입력이라면
        //결제타입 변경
        if (parseCommaInt(card.value) != 0 && parseCommaInt(cash.value) != 0) {
            paymenttype.value = "4";
        } else {
            if (parseCommaInt(card.value) > 0)
                paymenttype.value = "1";
            else if (parseCommaInt(cash.value) > 0)
                paymenttype.value = "2";
        }


        //미수금 계산
        var only_cash_couponprice = parseCommaInt(couponprice.value);
        var only_cash_lockerprice = lockerprice ? parseCommaInt(lockerprice.value) : 0;
        var only_cash_total = only_cash_couponprice + only_cash_lockerprice;

        var ccard_price = subVAT(null, parseCommaInt(card.value)); //카드를 부가세 뺀금액
        var ccash_price = parseCommaInt(cash.value); // 현금금액
        var cremain = parseCommaInt(remain.value); //미수금은 현금기준
        var cdiscount = parseCommaInt(discount.value); //할인금

        //카드입력이라면
        if (type == 30) {
            remain.value = CommaString(only_cash_total - (ccard_price + ccash_price + cdiscount));
        }
        //현금입력이라면
        else if (type == 31) {
            remain.value = CommaString(only_cash_total - (ccard_price + ccash_price + cdiscount));
        }
        //미수금 입력이라면
        else if (type == 32) {
            ccard_price = only_cash_total - (cremain + ccash_price + cdiscount);
            card.value = CommaString(addVAT(null, ccard_price));
        }
        //할인금금 입력이라면
        else if (type == 33) {
            ccard_price = only_cash_total - (cremain + ccash_price + cdiscount);
            card.value = CommaString(addVAT(null, ccard_price));
        }

        var ctotal = ccard_price + ccash_price + cdiscount;


        if (only_cash_total != ctotal) {
            cremain = only_cash_total - ctotal;
            remain.value = CommaString(cremain);
        }

    } else {

        if (paymenttype.value == 1) {
            card.value = CommaString(coupon_price + loc_price);
            cash.value = "0";
            remain.value = "0";
            discount.value = "0";

        } else if (paymenttype.value == 2) {
            card.value = "0";
            cash.value = CommaString(coupon_price + loc_price);
            remain.value = "0";
            discount.value = "0";
        }
    }


    //card -값을 없애기 위함
    if (parseCommaInt(card.value) < 0) {
        cash.value = parseCommaInt(cash.value) + parseCommaInt(card.value);
        card.value = "0";
    }


    //결제타입 자동변경
    if (parseCommaInt(card.value) != 0 && parseCommaInt(cash.value) != 0) {
        paymenttype.value = "4";
    } else {
        if (parseCommaInt(card.value) > 0)
            paymenttype.value = "1";
        else if (parseCommaInt(cash.value) > 0)
            paymenttype.value = "2";
    }

    //    clog("444 cvalue "+cvalue+" coupon_price "+coupon_price);
    /////////////////////////
    //결제총액 계산
    /////////////////////////
    //    if(couponprice)couponprice.value = CommaString(coupon_price);
    //    if(lockerprice)lockerprice.value = paymenttype.value && parseInt(paymenttype.value) == 1 ? CommaString(subVAT(null,loc_price)) : CommaString(loc_price);
    //    totalprice.value = CommaString(loc_price+parseCommaInt(couponprice.value));
    totalprice.value = CommaString(parseCommaInt(card.value) + parseCommaInt(cash.value) + parseCommaInt(remain.value) + parseCommaInt(discount.value));
    totalremain.value = CommaString(parseCommaInt(card.value) + parseCommaInt(cash.value));

}

function update_user_coupon(key, istermtype, useruid, before_couponid, before_paymentid, str_coupon, isrepay, isnotpayment) {
    var termtype_coupon = document.getElementById("c_termtype_coupon_" + key);
    var counttype_addcount = document.getElementById("c_counttype_addcount_" + key);
    var c_constructor = document.getElementById("c_constructor_" + key);
    var starttime = document.getElementById("c_starttime_" + key);
    var endtime = document.getElementById("c_endtime_" + key);
    var holdingday = document.getElementById("c_holdingday_" + key);
    var c_gxcount = document.getElementById("c_gxcount_" + key);
    var couponprice = document.getElementById("c_couponprice_" + key);
    var lockermonth = document.getElementById("c_lockermonth_" + key);
    var lockerservicemonth = document.getElementById("c_lockerservicemonth_" + key);
    var lockerprice = document.getElementById("c_lockerprice_" + key);
    var totalprice = document.getElementById("c_totalprice_" + key);
    var totalremain = document.getElementById("c_totalremain_" + key);
    var paymenttype = document.getElementById("c_paymenttype_" + key);
    var note = document.getElementById("c_note_" + key);
    var coupon = JSON.parse(str_coupon);
    var isnotpayment = coupon.mbsname.indexOf(EXCEL_COUPON) >= 0 ? true : false;
    if (isrepay) coupon.isrepay = "1" // 환불인지 체크
    clog("coupon = ", coupon);
    if (coupon.mbstype == TYPE_GX) coupon.mbsmaxcount = c_gxcount.value;
    coupon.mbsmaxholdingday = holdingday.value;
    if (istermtype == 1) {
        if (!isnotpayment)
            if (!termtype_coupon.value || termtype_coupon.value && parseInt(termtype_coupon.value) == 0) {
                alertMsg("회원권을 선택해 주세요.");
                return;
            }
    } else {
        if (!counttype_addcount.value || counttype_addcount.value && parseInt(counttype_addcount.value) == 0) {
            alertMsg("횟수는 최소 1회이상 입력해 주세요.");
            return;
        }
    }

    if (!starttime.value || !endtime.value || !couponprice.value || !paymenttype.value) {
        if (!starttime.value) {
            alertMsg("시작일을 선택해주세요.");
            return;
        } else if (!endtime.value) {
            alertMsg("종료일을 선택해주세요.");
            return;
        } else if (!isnotpayment && !couponprice.value) {
            alertMsg("가격을 입력해주세요.");
            return;
        } else if (!isnotpayment && !paymenttype.value) {
            alertMsg("결제타입을 선택해주세요.");
            return;
        }

    }

    var selected_coupon = null;
    for (var i = 0; i < simple_mbs_coupons.length; i++) {
        //기간제 
        if (istermtype == 1 && parseInt(simple_mbs_coupons[i]["mbs_idx"]) == parseInt(termtype_coupon.value)) {
            selected_coupon = simple_mbs_coupons[i];
            break;
        }
        //        //횟수제
        //        else if (istermtype == 0 &&  parseInt(simple_mbs_coupons[i]["mbs_idx"]) == parseInt(counttype_coupon.value)){
        //            selected_coupon = simple_mbs_coupons[i];
        //            break;
        //        }

    }
    if (istermtype == 0) selected_coupon = coupon;
    var title = "회원권 수정";
    var message = "해당 회원권을 수정하시겠습니까?";
    showModalDialog(document.body, title, message, "수정하기", "취소", function () {

        updateCoupondata(key, istermtype, useruid, before_couponid, before_paymentid, coupon);

    }, function (err) {
        hideModalDialog();

    });
}
//수강권 업그레이드
function upgrade_user_coupon(key, istermtype, useruid, before_couponid, before_paymentid, str_coupon) {
    var termtype_coupon = document.getElementById("c_termtype_coupon_" + key);
    var counttype_addcount = document.getElementById("c_counttype_addcount_" + key);
    var c_constructor = document.getElementById("c_constructor_" + key);
    var starttime = document.getElementById("c_starttime_" + key);
    var endtime = document.getElementById("c_endtime_" + key);
    var holdingday = document.getElementById("c_holdingday_" + key);
    var c_gxcount = document.getElementById("c_gxcount_" + key);
    var couponprice = document.getElementById("c_couponprice_" + key);
    var lockermonth = document.getElementById("c_lockermonth_" + key);
    var lockermonth = document.getElementById("c_lockermonth_" + key);
    var lockerprice = document.getElementById("c_lockerprice_" + key);
    var totalprice = document.getElementById("c_totalprice_" + key);
    var totalremain = document.getElementById("c_totalremain_" + key);
    var paymenttype = document.getElementById("c_paymenttype_" + key);
    var note = document.getElementById("c_note_" + key);
    var coupon = JSON.parse(str_coupon);
    var groupid = coupon.groupid ? coupon.groupid : random_string();

    coupon["groupid"] = groupid;
    //    clog("coupon = ",coupon);
    if (coupon.mbstype == TYPE_GX) coupon.mbsmaxcount = c_gxcount.value;
    coupon.mbsmaxholdingday = holdingday.value;
    if (istermtype == 1) {
        if (!termtype_coupon.value || termtype_coupon.value && parseInt(termtype_coupon.value) == 0) {
            alertMsg("회원권을 선택해 주세요.");
            return;
        }
    } else {
        //if(!counttype_addcount.value || counttype_addcount.value && parseInt(counttype_addcount.value) == 0){
        if (!counttype_addcount.value || counttype_addcount.value && parseInt(counttype_addcount.value) < 0) {
            alertMsg("추가횟수는 최소 1회이상 입력해 주세요.");
            return;
        }
    }

    if (!starttime.value || !endtime.value || !couponprice.value || !paymenttype.value) {
        if (!starttime.value) {
            alertMsg("시작일을 선택해주세요.");
        } else if (!endtime.value) {
            alertMsg("종료일을 선택해주세요.");
        } else if (!couponprice.value) {
            alertMsg("가격을 입력해주세요.");
        } else if (!paymenttype.value) {
            alertMsg("결제타입을 선택해주세요.");
        }
        return;
    }

    var selected_coupon = null;
    for (var i = 0; i < simple_mbs_coupons.length; i++) {
        //기간제 
        if (istermtype == 1 && parseInt(simple_mbs_coupons[i]["mbs_idx"]) == parseInt(termtype_coupon.value)) {
            selected_coupon = simple_mbs_coupons[i];
            break;
        }
        //        //횟수제
        //        else if (istermtype == 0 &&  parseInt(simple_mbs_coupons[i]["mbs_idx"]) == parseInt(counttype_coupon.value)){
        //            selected_coupon = simple_mbs_coupons[i];
        //            break;
        //        }

    }
    //수강추가
    if (istermtype == 0) selected_coupon = coupon;
    var title = "회원권 변경";
    var message = "해당 회원권을 변경하시겠습니까?";
    showModalDialog(document.body, title, message, "변경하기", "취소", function () {
        if (istermtype == 1 && coupon.mbstype != TYPE_GX) {
            var isremovelocker = 0; //라커기록 삭제유무 1 : 삭제 , 0 : 삭제안함
            var isdeletepayment = "N"; //N : 결제기록은삭제하지 않음 , D : 결제기록도삭제
            upgradePaymentData(before_paymentid, before_couponid, useruid, "D", isremovelocker, isdeletepayment, groupid, function (result) {
                if (result == 0) { //succes
                    createCoupondata(key, istermtype, useruid, before_couponid, before_paymentid, coupon);
                } else {
                    alertMsg("업데이트를 하지 못하였습니다.");
                }
            });
        } else {
            createCoupondata(key, istermtype, useruid, before_couponid, before_paymentid, coupon);
        }

    }, function (err) {
        hideModalDialog();

    });
}
