        var loc_month = lockermonth && lockermonth.value ? parseInt(lockermonth.value) : 0;
        var loc_servicemonth = lockerservicemonth && lockerservicemonth.value ? parseInt(lockerservicemonth.value) : 0;
        var mbsmaxcount = istermtype == 1 ? selected_coupon.mbs_max_count : parseInt(counttype_addcount.value);


        var totalprice = parseCommaInt(totalprice.value);
