        var mbstype = istermtype == 1 ? selected_coupon.mbs_type : coupon.mbstype;
        var mbsname = istermtype == 1 ? selected_coupon.mbs_name : coupon.mbsname;
        var mbsdesc = istermtype == 1 ? selected_coupon.mbs_desc : coupon.mbsdesc;
