function isJsonString(str) {
    try {
        var json = JSON.parse(str);
        return (typeof json === 'object');
    } catch (e) {
        return false;
    }
}
function isJsonObject(obj) {
    return obj !== null && typeof obj === 'object' && !Array.isArray(obj);
}
