function checkPaidMember(rows) {
    var centercode = getData("nowcentercode");
    var new_rows = [];
    for (var i = 0; i < rows.length; i++) {
        var starttime = rows[i].mem_starttime;
        var endtime = rows[i].mem_endtime;
        var membership = rows[i].mem_membership ? JSON.parse(rows[i].mem_membership) : [];
        var isoutmember = false; //유효회원이 아닌사람
        var outcoupons = [];
        var incoupons = [];
        //의심가는  환불 , 삭제 쿠폰들을 수집한다.
        for (var j = 0; j < membership.length; j++) {
            if (membership[j] && membership[j].mbsusecentercode == centercode) {
                //환불된 쿠폰
                if (membership[j].repay && parseInt(membership[j].repay) < 0 || membership[j].isdelete && membership[j].isdelete == "D") { //환불된 쿠폰                        
                    outcoupons.push(membership[j]);
                    //                        clog("의심쿠폰");
                } else {
                    //GX일때는 횟수가 모두소진되었는지 체크한다.
                    var mbstype = membership[j].mbstype;
                    var maxcount = getMbsMaxCount(membership[j]);
                    var usecount = membership[j].usecount ? parseInt(membership[j].usecount) : 0;
                    if(mbstype != TYPE_GX || mbstype == TYPE_GX && maxcount == 0 || mbstype == TYPE_GX && maxcount > 0 && usecount < maxcount)
                        incoupons.push(membership[j]);
                }
            }
        }
        //해당쿠폰중에 비교한다.
        if (incoupons.length == 0) {
            isoutmember = true;
            //                clog("aaa",outcoupons);
        } else if (incoupons > 0) {
            for (var c = 0; c < incoupons.length; c++) {
                var dday = getDay(incoupons.endtime, getToday());
                if (dday > 0) // 오늘보다 이후 쿠폰 즉 다음예약한 쿠폰이 있다면 유효회원이다. break
                    break;
            }
        }
        if (!isoutmember) new_rows.push(rows[i]);
    }
    return new_rows;
}

