function findTodayInputUser(uid) {
    var idx = -1;
    
    var firsttime = "";
    var lasttime = ""; 
    for (var i = 0; i < todayinputlist.length; i++) {
        if (todayinputlist[i].useruid == uid) {
            idx = i;
            break;
        }
    }
    for (var i = 0; i < todayinputlist.length; i++) {
        if (todayinputlist[i].useruid == uid) {
            //출근시간
            if(firsttime == "" || firsttime != "" && compare_date(firsttime,todayinputlist[i].date) > 0) 
                firsttime = todayinputlist[i].date;
            
            //퇴근시간 마지막 찍은시간
            if(lasttime == "" || lasttime != "" && compare_date(lasttime,todayinputlist[i].date) < 0) 
                lasttime = todayinputlist[i].date;
        }
    }
    if (idx >= 0){
        todayinputlist[idx].firsttime = firsttime;
        todayinputlist[idx].lasttime = lasttime;
        
        return todayinputlist[idx];
    }
        
    else
        return null;
}

function getNowHis() {

    var now = new Date();
    var hh = now.getHours() < 10 ? "0" + now.getHours() : "" + now.getHours();
    var mm = now.getMinutes() < 10 ? "0" + now.getMinutes() : "" + now.getMinutes();
    var ss = now.getSeconds() < 10 ? "0" + now.getSeconds() : "" + now.getSeconds();
    return hh + ":" + mm + ":" + ss;
}

function getNowHHMM() {

    var now = new Date();
    var hh = now.getHours() < 10 ? "0" + now.getHours() : "" + now.getHours();
    var mm = now.getMinutes() < 10 ? "0" + now.getMinutes() : "" + now.getMinutes();

    return hh + ":" + mm;
}

