var global_mypoint = 0;
var global_sms_sendprice = 0; //sms건당금액
var global_lms_sendprice = 0; //lms건당금액
var global_push_sendprice = 0; //푸시건당금액
var global_topic_sendprice = 0; //주제별건당금액

function getMYChargePoint() {
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");


    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "getchargepoint",
    }

    clog("**** test ", senddata);

    if (isPermission(210)) //충전하기 메세지창 권한
        CallHandler("adm_get", senddata, function (res) {

            if (res.code == 100) {
                var groupdata = res.message;
                if (groupdata) {
                    var mypoint = groupdata.gr_grouppoint;
                    var smsprice = groupdata.gr_smsprice; //건당금액
                    var lmsprice = groupdata.gr_lmsprice; //건당금액
                    var pushprice = groupdata.gr_pushprice; //건당금액
                    var topicprice = groupdata.gr_topicprice; //건당금액

                    global_mypoint = mypoint;
                    global_sms_sendprice = smsprice;
                    global_lms_sendprice = lmsprice;
                    global_push_sendprice = pushprice;
                    global_topic_sendprice = topicprice;

                    var id_mychargepoint = document.getElementById("id_mychargepoint");
                    var id_sms_count = document.getElementById("id_sms_count");
                    var id_lms_count = document.getElementById("id_lms_count");
                    var id_push_count = document.getElementById("id_push_count");


                    if (id_mychargepoint) id_mychargepoint.innerHTML = "" + TXT_WON + CommaString(mypoint);

                    if (id_sms_count) id_sms_count.innerHTML = mypoint > 0 && smsprice > 0 ? parseInt(mypoint / smsprice) : 0;
                    if (id_lms_count) id_lms_count.innerHTML = mypoint > 0 && lmsprice > 0 ? parseInt(mypoint / lmsprice) : 0;
                    if (id_push_count) id_push_count.innerHTML = mypoint > 0 && pushprice > 0 ? parseInt(mypoint / pushprice) : 0;


                }



            }
        }, function (err) {

        });
}

function updateMyChargePoint(addprice, callback) {
    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");


    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "checkchargepoint",
        value: {
            "amount": addprice,
            "orderId": orderId,
            "orderName": orderName,
            "customerName": customerName
        }
    }
    CallHandler("adm_get", senddata, function (res) {
        callback(res);
    }, function (err) {
        callback(null);
    });
}


