function C_ComboBox(parentid, id, default_text, objs, boxwidth, scale, functionname, isselected) {
    //test customCombobox code
    if (!scale) scale = 1;
    var combobox = createCustomComboBox(id, default_text, objs, boxwidth, scale, functionname, isselected);
    var parent = document.getElementById(parentid);
    parent.innerHTML = "";
    parent.append(combobox);

}

function C_ComboBoxTag(id, default_text, objs, boxwidth, scale, functionname, isselected) {
    //test customCombobox code
    if (!scale) scale = 1;
    var combobox = createCustomComboBox(id, default_text, objs, boxwidth, scale, functionname, isselected);
    var div = document.createElement("div");
    div.append(combobox);
    return div.innerHTML;

}

function createCustomComboBox(id, dtext, objs, boxwidth, scale, callbackfunction, isselected) { //scale = 0.1 ~ 3.1 대충
    //<div class="dropdown-divider"></div>// 구분선 예제
    //<a class="dropdown-item" onclick="userDropdownClick('','==선택하세요==','')">==선택하세요==</a>  //기본선택 예제
    //<a class="dropdown-item" onclick="userDropdownClick('111','선택11','arrow_l')"><img src='./img/arrow_l.png' style='height:25px;margin-top:-10px;'/>선택11</a>// 목록 예제
    if (!callbackfunction) callbackfunction = "aaa";
    if (!scale) scale = 1;
    var div = document.createElement("div");
    var div_width = parseInt(boxwidth * scale);
    var block_height = parseInt(30 * scale);
    var fontsize = parseInt(20 * scale);
    var img_margintop = -10 * scale;
    var width = div_width > 0 ? div_width + "px" : "100%";
    div.style.width = width;
    var ui = document.createElement("ui");
    ui.class = "navbar-nav ml-auto";
    div.append(ui);
    clog(" screen.height; " + screen.height);
    var main_tag = "<text style='font-size:" + fontsize + "px'>" + dtext + "</text>";
    var list_tag = "<a class='dropdown-item' style='height:" + block_height + "px' onclick='customComboClick(\"" + id + "\",\"\",\"" + dtext + "\",\"\" , " + scale + ",\"" + callbackfunction + "\")' style='height:" + block_height + "px;float:center'><text style='font-size:" + fontsize + "px'>" + dtext + "<text></a>";
    for (var i = 0; i < objs.length; i++) {
        var obj = objs[i];
        list_tag += "<a class='dropdown-item' onclick='customComboClick(\"" + id + "\",\"" + obj.value + "\",\"" + obj.text + "\",\"" + obj.imgname + "\", " + scale + ",\"" + callbackfunction + "\")'  style='width:height:" + block_height + "px;float:center'><img src='" + obj.imgname + "' style='height:" + block_height + "px;margin-top:" + img_margintop + "px;'/>&nbsp;<text style='font-size:" + fontsize + "px'>" + obj.text + "</text></a>";
        if (i == isselected) main_tag = "<img src='" + obj.imgname + "' style='height:" + block_height + "px;margin-top:" + img_margintop + "px;'/>&nbsp;<text style='font-size:" + fontsize + "px'>" + obj.text + "</text>";

    }
    var radius = 4 * scale;
    var cComboTag =

        "<a class='nav-link dropdown-toggle' id='" + id + "' href='#' role='button' data-toggle='dropdown' aria-haspopup='false' aria-expanded='false'  style='height:auto;background-color:white;border:1px solid #CED4DA ;border-radius: " + radius + "px;' >" + main_tag + "</a>" +
        "<div class='dropdown-menu dropdown-menu-right' aria-labelledby='" + id + " position='absolute' style='max-height:600px;overflow-y:auto'>" + list_tag + "</div>";
    //    clog("cComboTag "+cComboTag);
    ui.innerHTML = cComboTag;
    return div;

}

function customComboClick(id, value, text, imgname, scale, callbackfunction) {
    //    clog("aa userDropdownClick : "+value+" : "+text+" : ");
    var block_height = parseInt(30 * scale);
    var fontsize = parseInt(20 * scale);
    //    clog("scale is ",scale);
    var img_margintop = -10 * scale;
    var userDropdown = document.getElementById(id);
    userDropdown.innerHTML = imgname ? "<img id='" + id + "_img' src='" + imgname + "' style='height:" + block_height + "px;margin-top:" + img_margintop + "px;'/>&nbsp;<text id='" + id + "_text' style='font-size:" + fontsize + "px'>" + text + "</text><text id='" + id + "_value' style='display:none'>" + value + "</text>" : "<text id='" + id + "_text' style='font-size:" + fontsize + "px'>" + text + "</text><text id='" + id + "_value' style='display:none'>" + value + "</text>";

    var arg = getCustomComboData(id);
    eval(callbackfunction)(arg);
}

function aaa(arg) {
    clog("aaa arg ", arg);
}

function executeFunctionByName(functionName, context /*, args */ ) {
    var args = Array.prototype.slice.call(arguments, 2);
    var namespaces = functionName.split(".");
    var func = namespaces.pop();
    for (var i = 0; i < namespaces.length; i++) {
        context = context[namespaces[i]];
    }
    return context[func].apply(context, args);
}
//커스텀 콤보박스 값 가져오기
function getCustomComboData(id) {
    var img = document.getElementById(id + "_img");
    var value = document.getElementById(id + "_value").innerHTML;
    var text = document.getElementById(id + "_text").innerHTML;
    var rdata = img ? {
        "value": value,
        "text": text,
        "img": img.src
    } : {
        "value": value,
        "text": text
    };
    clog("rdata", rdata);
    return rdata;
}

