function getGXYearMonth(num) {
    var data = {
        "year": 0,
        "month": 0
    };
    data.year = num % 12 == 0 ? parseInt(num / 12) - 1 : parseInt(num / 12);
    data.month = num % 12 == 0 ? 12 : num % 12;
    return data;
}

function C_Clone(obj) {
    if (obj === null || typeof (obj) !== 'object')
        return obj;
    var copy = obj.constructor();
    for (var attr in obj) {
        if (obj.hasOwnProperty(attr)) {
            copy[attr] = obj[attr];
        }
    }
    return copy;
}

function VAT(mbsidx) {

    if (mbsidx) {
        var vat = 0;
        for (var i = 0; i < allmembership.length; i++) {
            if (parseInt(allmembership[i].mbs_idx) == parseInt(mbsidx)) {
                vat = parseInt(allmembership[i].mbs_vat);
                break;
            }
        }
        return vat;
    } else {
        return global_vat;
    }


    //    return global_vat;
}

function addVAT(mbsidx, price, mbsvat) {
    var vat = mbsvat ? parseInt(mbsvat) : VAT(mbsidx);
    clog("vat " + vat);
    price = price * ((100 + vat) / 100);
    clog("price " + price);
    return parseInt(price);
}

function subVAT(mbsidx, price, mbsvat) {
    var vat = mbsvat ? parseInt(mbsvat) : VAT(mbsidx);
    clog("vat " + vat);
    price = (price / (100 + vat)) * 100;
    clog("price " + price);
    return parseInt(price);
}

