function getMessageListTag(rows) {

    if(!rows)return;
    
    rows.sort(sort_by('startdate', true, (a) => a.toUpperCase()));
    var div_messagelist_table = document.createElement("div");
    var table = document.createElement("table");
    div_messagelist_table.appendChild(table);

    table.border = "1";
    table.style.width = "100%";

    table.className = "table table-bordered fmont";

   

    table.innerHTML = "<thead><tr style='background-color:#e0e9e9;font-size:12px;text-align:center;' align='center' style='margin:10px;'><th>순번</th><th>보낸시간</th><th>제목</th><th>메세지</th></tr></tr></thead><tfoot></tfoot><tbody></tbody>";
    var head = table.getElementsByTagName("thead")[0];
    var body = table.getElementsByTagName("tbody")[0];
    var foot = table.getElementsByTagName("tfoot")[0];
    var len = rows.length;
    if (len > 0) {
        for (var i = 0; i < len; i++) {
            var data = rows[i];
//            console.log("data is ",data);
            var brow = body.insertRow();
            brow.align = "center";
            brow.style.padding = "10px";
            brow.style.backgroundColor = data.checkintime ? "#54ca8b22" : "#009ef722";
//            console.log("data ",data);
            var isselected = true;
            var isdelete = false;
            CellInsert(brow, isdelete, isselected, i + 1); // 순번
            CellInsert(brow, isdelete, isselected, data.startdate); // 보낸시간
            CellInsert(brow, isdelete, isselected, data.title); // 제목
            CellInsert(brow, isdelete, isselected, data.body); // 메세지내용
        }
    }
    return div_messagelist_table.innerHTML;



}
function getGXTabReservationTag(rows, type) {
    var arr_couponids = [];
    var coupons = {};
    var len = 0;
    for(var i = 0 ; i < rows.length; i++){
        var couponid = rows[i].couponid;
        if(!coupons[couponid]){
            coupons[couponid] = [];
            arr_couponids.push(couponid);
            len++;
        }
        coupons[couponid].push(rows[i]);
    }
//    Object.entries(coupons).sort.sort(([a],[b]) => a < b? -1: 1 ); //오름차순정렬    
    coupons = sortCouponsByDate(coupons, false);//내림차순정렬
    
    console.log("coupons ",coupons);
    var tab_tags = "<ul class='nav nav-tabs'>";
    var now_couponid = "";
    
    for(key in coupons){
        if(!now_couponid)now_couponid = key;
        var active = now_couponid == key ? "active" : "";
        if(type == 0 || type == 2){
            
            var reservation_len = 0;
            var qrcheckin_len = 0;
            for(var i = 0 ; i< coupons[key].length; i++){
                if(parseInt(coupons[key][i].type) == 0){
                    reservation_len++;
                }else if(parseInt(coupons[key][i].type) == 2){
                    qrcheckin_len++;
                }
            }
            var title_tag = "<span style='float:left'>"+key.substr(0,10)+"</span><span style='float:right'><svg style='width:10px;height:10px'><rect width='10' height='10' style='fill:#009ef7' title='예약완료'></rect></svg>&nbsp;<text class='fmont' style='font-size: 12px; color:#3f4254;text-align:left; font-weight:500;'>"+reservation_len+"</text>&nbsp;&nbsp;<svg style='width:10px;height:10px'><rect width='10' height='10' style='fill:#54ca8b' title='QR출석완료'></rect></svg>&nbsp;<text class='fmont' style='font-size: 12px; color:#3f4254;text-align:left; font-weight:500;'>"+qrcheckin_len+"</text></span>";    
        }else{
            var len = coupons[key].length;
            var title_tag = "<span style='float:left'>"+key.substr(0,10)+"</span><span style='float:right'><svg style='width:10px;height:10px'><rect width='10' height='10' style='fill:#f0426b' title='대기신청'></rect></svg>&nbsp;<text class='fmont' style='font-size: 12px; color:#3f4254;text-align:left; font-weight:500;'>"+len+"</text></span>";    
        }
        
        
        tab_tags += "<li class='nav-item'><a href='#"+key+"' id='gxtabli_"+key+"' style='height:40px' class='nav-link "+active+"' data-toggle='tab' onclick='activaGXReservationTab(\""+key+"\",\""+setJSONStringToParamString(arr_couponids)+"\")'>"+title_tag+"</a></li>";
    }
    tab_tags += "</ul>";
    tab_tags += "<div class='tab-content' id='tabs'>";
    for(key in coupons){
         
         tab_tags += "<div class='tab-pane' id='\""+key+"\"' >"+getGXReservationTag(coupons[key], type)+"</div>";
    }
    tab_tags += "</div>";
   
    //목록 삽입
    for(key in coupons){
        var display = now_couponid == key ? "block" : "none";
         tab_tags += "<div id='div_tabdata_"+key+"' style='display:"+display+"'>"+getGXReservationTag(coupons[key], type)+"</div>";
    }
    
    return tab_tags;
    
}
//var coupons = {"2022-11-18 21:52:39":[4,5,6,7], "2023-02-20 20:06:42":[3,2]}; 오브젝트를 key를 기준으로 정렬
function sortCouponsByDate(coupons, ascending) {
  var sortedKeys = Object.keys(coupons).sort(function(a, b) {
    if (ascending) {
      return new Date(a) - new Date(b);
    } else {
      return new Date(b) - new Date(a);
    }
  });
  
  var sortedCoupons = {};
  for (var i = 0; i < sortedKeys.length; i++) {
    sortedCoupons[sortedKeys[i]] = coupons[sortedKeys[i]];
  }
  
  return sortedCoupons;
}
function activaGXReservationTab(key,str_couponids){
 
    var couponids = JSON.parse(str_couponids);
    for (var i = 0; i < couponids.length; i++){
         var cid = couponids[i];
         document.getElementById("div_tabdata_" + cid).style.display = cid == key ? "block" : "none";

         var tab = document.getElementById("gxtabli_"+key);
         
         if(key == cid && tab.className.indexOf("active") < 0) tab.classList.add("active");
         if(key == cid && tab.className.indexOf("active") >= 0)tab.className = tab.className.replace("active","");
     }
};

//type = : 0 :예약완료 , 2: QR출석완료 , 5 : 대기신청
function getGXReservationTag(rows, type) {


        rows.sort(sort_by('roomid', true, (a) => a.toUpperCase()));
    var div_member_table = document.createElement("div");
    var table = document.createElement("table");
    div_member_table.appendChild(table);

    table.border = "1";
    table.style.width = "100%";
    table.style.color = "gray";

    table.className = "table table-bordered fmont";

   // var qrtype = type == 2 ? "<th>QR출석시간</th>" : "";
     var qrtype = "<th>QR출석시간</th>"; //무조건 QR 출석시간을 표시한다.

    table.innerHTML = "<thead><tr style='background-color:#e0e9e9;font-size:12px;text-align:center;' align='center' style='margin:10px;'><th>순번</th><th>날짜</th><th>회원권등록일</th><th>강좌명</th><th>강사명</th><th>강좌시간</th>" + qrtype + "<th>버튼</th></tr></tr></thead><tfoot></tfoot><tbody></tbody>";
    var head = table.getElementsByTagName("thead")[0];
    var body = table.getElementsByTagName("tbody")[0];
    var foot = table.getElementsByTagName("tfoot")[0];
    var len = rows.length;
    if (len > 0) {
        for (var i = 0; i < len; i++) {
            var data = rows[i];
            console.log("data is ",data);
            var brow = body.insertRow();
            brow.align = "center";
            brow.style.padding = "10px";
            brow.style.backgroundColor = data.checkintime ? "#54ca8b22" : "#009ef722";
            if(type == 5)brow.style.backgroundColor = "#f0426b22";
//            console.log("data ",data);
            
            var ymd = data.date;
            var hour = parseInt(data.hour) < 10 ? "0"+data.hour : data.hour;
            var min = parseInt(data.min) < 10 ? "0"+data.min : data.min;
            var room_starttime = ymd+" "+hour+":"+min+":00";//강좌 시작시간으로 체크한다.
            //미래 시간이라면 
            if(isNowTimeMinOver(room_starttime) > 0){
                brow.style.fontWeight = "bold";
                brow.style.color = "#3f4254";     
                brow.style.backgroundColor = data.checkintime ? "#54ca8b55" : "#009ef755";
                if(type == 5)brow.style.backgroundColor = "#f0426b55";
            }
//                brow.style.backgroundColor = "#fffd0022";
                
            
            var isselected = true;
            var isdelete = false;
            CellInsert(brow, isdelete, isselected, i + 1); // 순번
            CellInsert(brow, isdelete, isselected, data.date); // 날짜
            CellInsert(brow, isdelete, isselected, data.couponid.substr(0,10)); // 회원권 등록일 couponid
            CellInsert(brow, isdelete, isselected, data.roomname + "[" + data.roomdetailname + "]"); // 강좌명 ex) 강좌[세부강좌]
            CellInsert(brow, isdelete, isselected, data.roommanagername); // 강사명


            var hour_txt = parseInt(data.hour) < 13 ? "오전 " + data.hour + "시" + data.min + "분" : "오후 " + parseInt((data.hour) % 12) + "시 " + data.min + "분";
            CellInsert(brow, isdelete, isselected, hour_txt); // 시간


            //QR출석시간
             var checkin_txt = "";
            if (data.checkintime) {
                var h = stringGetHour(data.checkintime);
                var m = stringGetMin(data.checkintime);
                var checkin_txt = parseInt(h) < 13 ? "오전 " + h + "시" + m + "분" : "오후 " + parseInt((h) % 12) + "시 " + m + "분";
            }
            CellInsert(brow, isdelete, isselected, checkin_txt); // QR출석시간


            //                clog("data is ",data);
            var yy = parseInt(stringGetYear(data.date));
            var mm = parseInt(stringGetMonth(data.date));
            var dd = parseInt(stringGetDay(data.date));

            var yearmonthnum = yy * 12 + mm;

            var btn_delete_tag = isPermission(226) ? "<button onclick='remove_inuser(\"" + yearmonthnum + "\",\"" + data.roomid + "\",\"" + yy + "\",\"" + mm + "\",\"" + dd + "\",\"" + data.hour + "\",\"" + data.roomname + "\",\"" + data.username + "\",\"" + data.useruid + "\",\"userpage\")' style='border:0px;width:90px; height:35px;border-radius:5px;background-color:#009ef7;font-size: 14px; color:#ffffff;text-align:center; font-weight:700;' >삭제하기</button>" : "";
            CellInsert(brow, isdelete, isselected, btn_delete_tag); // 버튼

        }
    }
    return div_member_table.innerHTML;



}

function buildCalendar() {
    let firstDate = new Date(today.getFullYear(), today.getMonth(), 1);
    const monthList = ['1월', '2월', '3월', '4월', '5월', '6월', '7월', '8월', '9월', '10월', '11월', '12월'];
    const leapYear = [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    const notLeapYear = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    const headerYear = document.querySelector('.current-year-month');
    // 윤년 체크하기
    if (firstDate.getFullYear() % 4 === 0) {
        pageYear = leapYear;
    } else {
        pageYear = notLeapYear;
    }
    headerYear.innerHTML = today.getFullYear() + "년 " + monthList[firstDate.getMonth()]; //  `${monthList[firstDate.getMonth()]}&nbsp;&nbsp;&nbsp;&nbsp;${today.getFullYear()}`;
    makeElement(firstDate);
    showMain();
    currentDateget();
    resetInsert();
    setMiniCalendarData();//GX 유저 출석달력  
    
        
}
