function sendRemoveRoomUser(value, page) {


    var groupcode = getData("nowgroupcode");
    var centercode = getData("nowcentercode");

    var senddata = {
        groupcode: groupcode,
        centercode: centercode,
        type: "removeroomuser",
        value: value
    };
    CallHandler("adm_get", senddata, function (res) {
        code = parseInt(res.code);
        if (code == 100) {
            C_showToast("알림", res.message, function () {});
            if (page == "gxpage") reload_calendar_page();
            else if (page == "userpage") {
                hideModalDialog();

                header_search(value.useruid);
            }

        } else {
            alertMsg(res.message, function () {
                hideModalDialog();
            });
        }

    }, function (err) {
        alertMsg("네트워크 에러 ");

    });
}

var worker_push = new Worker(WORKER_PATH);
var worker_sms = new Worker(WORKER_PATH);

function C_SendWorker(type, datas, callback) {

    var msg = {
        "type": type,
        "datas": datas
    };

    if (type == "sendpushmessages") {
        worker_push.postMessage(msg);
        worker_push.onmessage = function (event) {
            //            clog("@@@@@@ worker Push Success!! Get Data Type "+event.data.type);
            //            clog(event.data.datas);
            //           clog("event",event);

            callback(event.data.datas);

        };
    } else if (type == "sendsmsmessages") {
        worker_sms.postMessage(msg);
        worker_sms.onmessage = function (event) {
            //            clog("@@@@@@ worker SMS Success!! Get Data Type "+event.data.type);
            //            clog(event.data.datas);
            //           clog("event",event);

            callback(event.data.datas);

        };
    }


}

function startWorker() {
    if (typeof (Worker) !== 'undefined') {

        if (typeof (worker_push) != 'undefined') {
            clog("worker_push terminate");
            worker_push.terminate();
        }
        worker_push = new Worker(WORKER_PATH);

        if (typeof (worker_sms) != 'undefined') {
            clog("worker_sms terminate");
            worker_sms.terminate();
        }
        worker_sms = new Worker(WORKER_PATH);


    }

}

