function isDevLocalHost(){
    var htype = window.location.hostname.indexOf("localhost") >= 0 ? "localhost" : "blackgym";
    var drtype = window.location.pathname.indexOf("dev") >= 0 ? "dev" : "real";

    if (htype == "blackgym" && drtype == "real") {
        return false;
    }else{
        return true;
    }
}
