function setZoom(mzoom){
    
    // 강제로 비율조정할때 사용
    if(!mzoom)mzoom = 1;
    
    var zoom = 100;
    var screen_width = $(window).width();
    var max_width = 375;
    zoom = (screen_width / max_width)*mzoom;
//    clog("screen_width "+screen_width);
    var width_percent = 100;
//    if (zoom > 1) zoom = 1;
    clog(" zoom "+zoom+ " width_percent "+width_percent);
    document.body.style.width = width_percent = width_percent+"%";
    document.body.style.zoom = width_percent = zoom+"";
    
    return zoom;
}
function getHolidays(dates){ //dates = pastedates
    var holidays = [];
    for(var i = 0 ; i < dates.length;i++){
        if(getDayOfWeek(dates[i]) == "일" || isCustomHoliday(dates[i])){
            holidays.push(dates[i]);
        }
    }
    return holidays;
}
function isCustomHoliday(mdate){
    //2006_1_28
    var y = stringGetYear(mdate);
    var m = parseInt(stringGetMonth(mdate));
    var d = parseInt(stringGetDay(mdate));
    var md = "_"+m+"_"+d;
    var ymd = y+"_"+m+"_"+d+" "; //반드시 빈공간이 있어야한다.
    
    var isin = false;
    for(var i = 0 ; i < yholiday.length;i++){
        if(yholiday[i][0].indexOf(md) >= 0){
            isin = true;
            break;
        }
    }
    if(!isin)
    for(var i = 0 ; i < uholiday.length;i++){
        if(uholiday[i][0].indexOf(ymd) >= 0){
            isin = true;
            break;
        }
    }
    console.log("mdate "+mdate+" isin "+isin);
    return isin;
}
function getDayOfWeek(mdate){ //ex) getDayOfWeek('2022-06-13')

    const week = ['일', '월', '화', '수', '목', '금', '토'];
    const dayOfWeek = week[new Date(mdate).getDay()];
    return dayOfWeek;

}
function getElementPos(el) {
    // yay readability

    var w = el ? el.scrollWidth : 0;
    var h = el ? el.scrollHeight : 0;
//    console.log("w is "+w+" h is "+h);
//        console.log("rect ",rect);
    for (var lx=0, ly=0;
         el != null;
         lx += el.offsetLeft, ly += el.offsetTop, el = el.offsetParent);
    return {x: lx,y: ly,w:w,h:h};
}

