function getGXPriceRuleUser(gxpricerule,userlen){
    var ruser = null;
    for (var i = 0; i < gxpricerule.user.length; i++) {
         var user = gxpricerule.user[i];
        if(user.len == userlen){
            ruser = user;
            break;
        }
    }
    return ruser;
}
function isinGXPriceRuleUser(gxpricerule,userlen){
    var flg = false;
    if(gxpricerule.user)
    for (var i = 0; i < gxpricerule.user.length; i++) {
         var user = gxpricerule.user[i];
        if(user.len == userlen){
            flg = true;
            break;
        }
    }
    return flg;
}
