function update_pricetype(idx){
        
    var tab_lesson = document.getElementById("tab_lesson");
    var tab_user = document.getElementById("tab_user");
    var div_pricetype_lesson = document.getElementById("div_pricetype_lesson");
    var div_pricetype_user = document.getElementById("div_pricetype_user");
    var tab_label_lesson = document.getElementById("tab_label_lesson");
    var tab_label_user = document.getElementById("tab_label_user");

    var div_pricetype_noshow = document.getElementById("div_pricetype_noshow");
    var div_pricetype_nobody = document.getElementById("div_pricetype_nobody");
    
    global_gxpricetype = idx;
    //강좌별
    if(idx == 0){
        tab_lesson.style.backgroundColor = "#f5f8fa";
        div_pricetype_lesson.style.display = "block";
        tab_label_lesson.style.fontWeight = "700";

        tab_user.style.backgroundColor = "#ffffff";
        div_pricetype_user.style.display = "none";
        tab_label_user.style.fontWeight = "300";

//        msetting.pricenamesetting[1].gxpricerule.pricetype = 0;
        tab_label_lesson.innerHTML = "<i class='fa-solid fa-check'></i>&nbsp;&nbsp;&nbsp;강좌별";
        tab_label_user.innerHTML = "수강인원별";

        div_pricetype_noshow.style.display = "block";
        div_pricetype_nobody.style.display = "block";
    }
    //수강인원별
    else {
         tab_lesson.style.backgroundColor = "#ffffff";
        div_pricetype_lesson.style.display = "none";
        tab_label_lesson.style.fontWeight = "300";

        tab_user.style.backgroundColor = "#f5f8fa";
        div_pricetype_user.style.display = "block";
        tab_label_user.style.fontWeight = "700";

//        msetting.pricenamesetting[1].gxpricerule.pricetype = 1;

        tab_label_lesson.innerHTML = "강좌별";
        tab_label_user.innerHTML = "<i class='fa-solid fa-check'></i>&nbsp;&nbsp;&nbsp;수강인원별";

        div_pricetype_noshow.style.display = "none";
        div_pricetype_nobody.style.display = "none";

    }
} 


