function sendWebhook() {
  const id = getData("nowcentercode");
    
  const url = `../../../ssapi/test1.php?id=${id}`;

  const xhr = new XMLHttpRequest();
  xhr.open('POST', url);
  xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
  xhr.onload = function() {
    console.log('Webhook sent successfully:', xhr.responseText);
  };
  xhr.onerror = function() {
    console.error('Webhook failed:', xhr.statusText);
  };
  xhr.send(`id=${id}&message=Hello+world!`);
}









