//입력된 6자리코드체크
 function inputIsConfirmEmail(id,callback) {
     var email = document.getElementById("email");
     var code = document.getElementById(id);
     var email_checkdiv = document.getElementById(id+"_checkdiv");
     var email_progress = document.getElementById(id+"_progress");
     
    
//       clog("00 inputIsEmail groupcode "+groupcode+" centercode "+centercode);
//       clog("inputIsEmail "+email.value);
    // 변수를 선언한다.
    var regExp = /^[0-9a-zA-Z]([-_.]?[0-9a-zA-Z])*@[0-9a-zA-Z]([-_.]?[0-9a-zA-Z])*\.[a-zA-Z]{2,}$/i;

    
    // 이메일 확인
    // 숫자인지 체크
    if(isNumeric(code.value) == false) {
//        alert("e-mail 형식이 일치하지 않습니다.\n다시 입력하여 주시기 바랍니다.");
        
        //이메일 형식에 맞지 않다.
        showEmailCheckIcon(id,"notuse");
//        email.value = "";
        code.focus();
    } else {
        
        //이메일 형식에 맞다
        //1초후에 이메일 중복을 체크한다.
        
        setTimeout(function(){
            showEmailCheckIcon(id,"loading");
            console.log("6자리코드 중복체크한다.");
            
            isEmailConfirmCheck(email.value, code.value, function(res){
                var code = parseInt(res.code);
                if(code == 100){
                    showEmailCheckIcon(id,"use");
                    callback(1);
                }else {
                    showEmailCheckIcon(id,"notuse");
                    callback(0);
                }
            },function(err){
                showEmailCheckIcon(id,"notuse");
                callback(0);
            })
        },1000);
    }
}

function isNumeric(value) {
  return !isNaN(Number(value));
}
