var code_count = 0;
function codeCountdownStart(){
    code_count = 240;
    var btn_send_emailcode = document.getElementById("btn_send_emailcode");

    var codeInterval = setInterval(function(){
        code_count--;
        var min = parseInt(code_count/60);
        var sec = code_count%60;
        btn_send_emailcode.innerHTML = min > 0 ? min+":"+sec : ""+sec;

        if(code_count < 0){
            clearInterval(codeInterval);
            codeCountdownStop();
        }
    },1000);
}
function codeCountdownStop(){
    var btn_send_emailcode = document.getElementById("btn_send_emailcode");
     btn_send_emailcode.innerHTML = "코드전송";
}
function removeReadonly(id) {
   const emailInput = document.getElementById(id);
    emailInput.removeAttribute('readonly'); // readonly 속성 제거
    emailInput.focus(); // 선택적으로 입력 필드에 포커스 설정
}
var before_channel_tab_idx = 0;
function onclick_channel_tab(tabidx) {
    if (before_channel_tab_idx != tabidx) {
        if (tabidx == 0) { //전체
            $("#select_channel_tab_0").show(200);
            $("#select_channel_tab_1").hide(100);
            

        } else { //남자라커
            $("#select_channel_tab_0").hide(100);
            $("#select_channel_tab_1").show(200);
            
        } 
        before_channel_tab_idx = tabidx;
    }
}

//중복제거 ["tests", "aaa", "bb", "test", "aaa", "bb"] 중복제거
function removeDuplicates(arr) {
  return [...new Set(arr)];
}
  
function animateHeight(divId, targetHeight, duration) {
    // 대상 div 가져오기
    var div = document.getElementById(divId);
    if (!div) {
        console.error(`Div with id "${divId}" not found.`);
        return;
    }

    // 초기 설정
    var startHeight = 0;
    div.style.height = startHeight + "px"; // 초기 높이 설정
    div.style.overflow = "hidden";        // 내용 오버플로 방지
    div.style.transition = `height ${duration}ms ease-in-out`; // CSS Transition 설정

    // 타겟 높이로 애니메이션
    setTimeout(() => {
        div.style.height = targetHeight + "px";
    }, 0);

    // 애니메이션 종료 후 초기화
    setTimeout(() => {
        div.style.transition = ""; // 애니메이션 완료 후 트랜지션 제거
    }, duration);
}

