function uploadFormContentProcess(type, _data,fileProgressId, progressBarId, img_files, isadd, callback){
    var fileProgress = document.getElementById(fileProgressId);
    var progressBar = document.getElementById(progressBarId);
    // FormData 객체 생성
    const formData = new FormData();

    // 폼 데이터 추가
    formData.append('value', JSON.stringify(_data) );
    formData.append("type", type);


    // 파일데이터 : 모든 파일 가능
    if(img_files.length > 0){
        for (var i = 0; i < img_files.length; i++) 
            formData.append("files[]", img_files[i]); //  각 파일을 'files[]' 키로 추가               
    }
   

    const xhr = new XMLHttpRequest();
    xhr.open("POST", FILE_UPLOAD_PLACE, true);

    xhr.upload.onprogress = function (event) {
        if (event.lengthComputable) {
            const percentComplete = Math.round((event.loaded / event.total) * 100);
            if(progressBar)progressBar.style.width = percentComplete + "%";
        }
    };
    C_ShowLoadingProgress();
    // Set up event listeners for the XMLHttpRequest
    xhr.onreadystatechange = function () {
        if (xhr.readyState === XMLHttpRequest.DONE) {
            C_HideLoadingProgress();
            if (xhr.status === 200) {

                // File upload successful
                console.log('File upload successful',xhr);
                var res = JSON.parse(xhr.response);
                if(res.code="100"){
                   callback("success");
                    
                }else{
                     //메일발송 실패
                   callback("error");
                }
                
            } else {
                // File upload failed
                console.error('File upload failed',xhr);
            }
        }
    };


    xhr.onerror = function () {
        console.error("Upload error.");
        if(progressBar)progressBar.style.width = "0%";
    };

    xhr.send(formData);
}
function uploadFormProcess(type, _data,fileProgressId, progressBarId, thumbId, imgId, isadd, callback){
    var fileProgress = document.getElementById(fileProgressId);
    var progressBar = document.getElementById(progressBarId);
    // FormData 객체 생성
    const formData = new FormData();

    // 폼 데이터 추가
    formData.append('value', JSON.stringify(_data) );
    formData.append("type", type);

    // 이미지 파일 추가 (썸네일)
    const thumbnailInput = document.getElementById(thumbId); // 썸네일 이미지 input 요소
    if (thumbnailInput && thumbnailInput.files.length > 0) {
        formData.append("pdthumb", thumbnailInput.files[0]);
    }else if (thumbnailInput.src && thumbnailInput.src.startsWith("data:image")) {
        // base64 이미지가 있을 경우 File 객체로 변환
        const base64Data = thumbnailInput.src;
        const file = base64ToFile(base64Data, `image_default.png`, "image/png");
        formData.append("pdthumb", file);
    } 

  // 이미지 파일 추가 (큰 이미지)
    const largeImageInput = document.getElementById(imgId); // 큰 이미지 input 요소
    if (largeImageInput && largeImageInput.files.length > 0) {
        formData.append("pdimg", largeImageInput.files[0]);
    }else if (largeImageInput.src && largeImageInput.src.startsWith("data:image")) {
        // base64 이미지가 있을 경우 File 객체로 변환
        const base64Data = largeImageInput.src;
        const file = base64ToFile(base64Data, `image_click.png`, "image/png");
        formData.append("pdimg", file);
    } 
    

    const xhr = new XMLHttpRequest();
    xhr.open("POST", FILE_UPLOAD_PLACE, true);

    xhr.upload.onprogress = function (event) {
        if (event.lengthComputable) {
            const percentComplete = Math.round((event.loaded / event.total) * 100);
            if(progressBar)progressBar.style.width = percentComplete + "%";
        }
    };
    C_ShowLoadingProgress();
    // Set up event listeners for the XMLHttpRequest
    xhr.onreadystatechange = function () {
        if (xhr.readyState === XMLHttpRequest.DONE) {
            C_HideLoadingProgress();
            if (xhr.status === 200) {

                // File upload successful
                console.log('File upload successful',xhr);
                var res = JSON.parse(xhr.response);
                if(res.code="100"){
                   callback("success");
                    
                }else{
                     //메일발송 실패
                   callback("error");
                }
                
            } else {
                // File upload failed
                console.error('File upload failed',xhr);
            }
        }
    };


    xhr.onerror = function () {
        console.error("Upload error.");
        if(progressBar)progressBar.style.width = "0%";
    };

    xhr.send(formData);
}
function uploadFileProcess(type, _data, input_id,  upload_progress_id, upload_percent_id, callback) {
        const div_uploadfile = document.getElementById("div_uploadfile");
        const input = document.getElementById(input_id);
        const progressBar = document.getElementById(upload_progress_id);
        const percentText = document.getElementById(upload_percent_id);
        
        input.onchange = function () {
            const file = input.files[0];
            if (!file) return;

            
            //동영상이 아닐대
            if (!file.type.startsWith('video/')) {
                 document.getElementById('thumbnailPreview').src = "";   
                clickInput(type, _data, file, progressBar, percentText, callback);
            }
            //동영상일때 
            else {
            
               extractVideoThumbnail(file, function(base64) {
                   if (base64) {
                        console.log("썸네일 "+base64);                      
                        _data.videothumb = base64;
                    } 
                   
                    clickInput(type, _data, file, progressBar, percentText, callback);
                }, 1.0);
            
            }
            
           
        };

        // 파일 선택창 열기
        input.click();
    }
function clickInput(type, _data, file, progressBar, percentText, callback){
        const formData = new FormData();
        formData.append('file', file);
         // 폼 데이터 추가
        formData.append('value', JSON.stringify(_data) );
        formData.append("type", type);
         
        const xhr = new XMLHttpRequest();

        console.log("clickInput _data is ",_data);
        // 서버 업로드 경로 생성: path + filename
//            const uploadUrl = path + encodeURIComponent(file.name);

        xhr.open('POST', FILE_UPLOAD_PLACE, true);

        // 업로드 진행률 표시
        xhr.upload.onprogress = function (e) {
            if (e.lengthComputable) {
                const percentComplete = Math.round((e.loaded / e.total) * 100);
                progressBar.value = percentComplete;
                percentText.innerText = percentComplete + '%';
            }
        };

        xhr.onloadstart = function () {
            progressBar.style.display = 'inline-block';
            progressBar.value = 0;
            percentText.innerText = '0%';
            div_uploadfile.style.display = "flex";
        };

        xhr.onload = function () {

            if (xhr.status === 200) {
                percentText.innerText = '✅ 업로드 완료';
                  var res = JSON.parse(xhr.response);
                if(callback)callback(res);
            } else {
                percentText.innerText = '❌ 업로드 실패: ' + xhr.status;
                if(callback)callback("error");
            }
        };

        xhr.onerror = function () {
            percentText.innerText = '❌ 네트워크 오류';
        };

        xhr.send(formData);
    }
function extractVideoThumbnail(file, callback, seekTo = 1.0) {
        const video = document.createElement('video');
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        canvas.width = 200;
        canvas.height = 200;

        video.preload = 'metadata';
        video.muted = true;
        video.playsInline = true; // 모바일 호환
        video.src = URL.createObjectURL(file);

        // 영상 메타데이터 로드되면 시간 설정
        video.onloadedmetadata = function () {
            if (video.duration < seekTo) seekTo = 0;
            video.currentTime = seekTo;
        };

        // seek 후 drawImage로 썸네일 추출
        video.onseeked = function () {
            try {
                const vw = video.videoWidth;
                const vh = video.videoHeight;

                // 중앙 자르기 (비율 유지)
                let sx = 0, sy = 0, sw = vw, sh = vh;
                if (vw > vh) {
                    sw = vh;
                    sx = (vw - sw) / 2;
                } else {
                    sh = vw;
                    sy = (vh - sh) / 2;
                }

                ctx.drawImage(video, sx, sy, sw, sh, 0, 0, 200, 200);
                const base64 = canvas.toDataURL('image/jpeg', 0.85);
                callback(base64);
            } catch (err) {
                console.error("drawImage 오류", err);
                callback(null);
            }

            URL.revokeObjectURL(video.src);
        };

        video.onerror = function (e) {
            console.error("video.onerror", e);
            callback(null);
        };
    }
function replaceTabsAndNewlinesWithSpaces(str) {
  return str.replace(/[\t\n\r]/g, ' ');
}

function click_thumb(idx){
    const thumbnailPreview = idx != undefined ? document.getElementById("thumbnail-preview_"+idx) : document.getElementById("thumbnail-preview");
    const inputPdThumb = idx != undefined ? document.getElementById("input_pd_thumb_"+idx) : document.getElementById("input_pd_thumb"); 
    inputPdThumb.click();
    inputPdThumb.addEventListener('change', (event) => {
        const file = event.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => {
                thumbnailPreview.src = e.target.result; // 미리보기 이미지 변경
            };
            reader.readAsDataURL(file);

//            resizeAndCropImage(file, 100,100, function (dataURL) {
//                 thumbnailPreview.src = dataURL; // 미리보기 이미지 변경
//            });
        }
    });
}
function click_img(idx){
    const imgPreview = idx != undefined ? document.getElementById("img-preview_" + idx) : document.getElementById("img-preview");
    const inputPdImg = idx != undefined ? document.getElementById("input_pd_img_" + idx) : document.getElementById("input_pd_img");
    const html_preview = document.getElementById("html_preview");
    const show_preview = document.getElementById("show_preview_"+idx);
    // change 이벤트 중복 등록 방지
    if (!inputPdImg.hasChangeHandler) {
        inputPdImg.addEventListener('change', (event) => {
            const file = event.target.files[0];
            if (file) {
                const reader = new FileReader();
                reader.onload = (e) => {
                   

                    imgPreview.src = e.target.result; // 미리보기 이미지 변경
                    show_preview.src = e.target.result;
                    show_preview.style.display = "block";
                    const tempimg = document.createElement("img");
                    tempimg.src = e.target.result;
                    tempimg.style.width = "100%";

                };
                reader.readAsDataURL(file);
            }
        });

        // 플래그로 중복 등록 방지
        inputPdImg.hasChangeHandler = true;
    }

    inputPdImg.click();
}
