//순서대로 정렬 int값 기준
function sortByKeyInt(arr, key, isUpper = false) {
  for (let i = 0; i < arr.length - 1; i++) {
    for (let j = 0; j < arr.length - i - 1; j++) {
      const a = parseInt(arr[j][key]);
      const b = parseInt(arr[j + 1][key]);

      let shouldSwap = false;
      if (isUpper) {
        // 내림차순 (큰 수부터) 정렬
        if (a < b) {
          shouldSwap = true;
        }
      } else {
        // 오름차순 (기본값) 정렬
        if (a > b) {
          shouldSwap = true;
        }
      }

      if (shouldSwap) {
        // Swap elements
        let temp = arr[j];
        arr[j] = arr[j + 1];
        arr[j + 1] = temp;
      }
    }
  }
  return arr;
}
